import { G, T, A, O, P } from './domains.js';

export const part3 = [
  {id:253,domain:P,question:"What is a security operations center (SOC)?",options:["A centralized team and facility monitoring and responding to security events 24/7","An internal team of compliance auditors that reviews organizational adherence to regulatory frameworks and security control standards","A physical room where servers are kept","A cloud-hosted SaaS vulnerability management application that aggregates scanner results and tracks remediation workflow tickets across the enterprise"],answer:0,explanation:"A SOC combines people, processes, and technology to continuously monitor, detect, analyze, and respond to security threats.",optionExplanations:["A SOC is the hub of continuous security monitoring, threat detection, and incident response operations.","Compliance audit teams assess regulatory adherence periodically; a SOC is an operational security function staffed 24/7 to detect, analyze, and respond to active security threats.","A data center is the physical server room; a SOC focuses on security monitoring and response.","A vulnerability management platform tracks patching and remediation; a SOC is a centralized team and facility staffed around the clock to monitor and respond to security events."]},
  {id:254,domain:G,question:"Which of the following describes the concept of tokenization in data security?",options:["Applying reversible AES-256 encryption to sensitive data fields so they can be decrypted using the corresponding encryption key when needed","Replacing sensitive data with a non-sensitive placeholder (token) that maps back to the original in a secure vault","Applying a one-way SHA-256 cryptographic hash function to sensitive data to produce a fixed-length digest for safe storage","Distributing fragments of sensitive records across multiple geographically separated servers to reduce the exposure from any single data breach"],answer:1,explanation:"Tokenization replaces sensitive data (like credit card numbers) with non-sensitive tokens; the mapping is in a secure token vault.",optionExplanations:["Encrypting data produces a ciphertext decryptable with the key; tokenization replaces data with a random token that has no mathematical relationship to the original, stored separately in a vault.","Tokenization substitutes sensitive values with tokens that have no exploitable mathematical relationship to the original.","Hashing is a one-way transformation producing a fixed digest; tokenization replaces data with a random placeholder token that maps back to the original only in a secure vault.","Distributing data across servers describes data sharding or secret splitting; tokenization replaces sensitive values with random tokens that can only be reversed via a separate secure vault."]},
  {id:255,domain:G,question:"What is the purpose of FIDO2 / WebAuthn?",options:["Enable passwordless authentication using hardware keys or device biometrics","Encrypt web browsing sessions end-to-end between the client and server","Manage the full issuance and revocation lifecycle of digital certificates","Provide fully encrypted email communication channels between two corresponding parties"],answer:0,explanation:"FIDO2/WebAuthn enables strong authentication via hardware security keys (YubiKey) or device biometrics, eliminating passwords.",optionExplanations:["FIDO2 provides strong, phishing-resistant authentication using public-key cryptography with hardware keys or biometrics.","TLS/HTTPS is what encrypts web sessions; FIDO2 instead handles the separate step of authenticating the user.","Certificate lifecycle management is handled by PKI systems, while FIDO2 is instead an authentication protocol.","Email encryption is handled by S/MIME and PGP, which is unrelated to FIDO2's web authentication purpose."]},
  {id:256,domain:T,question:"What is a RAT (Remote Access Trojan)?",options:["A legitimate, IT-sanctioned remote administration tool used for authorized support tasks","A specific software vulnerability discovered within legitimate remote desktop protocol software","Malware giving attackers hidden remote control of a victim's system","A specific technique used to bypass firewall rules and evade network filtering"],answer:2,explanation:"RATs silently install themselves and give attackers full remote control including file access, webcam, microphone, and keylogging.",optionExplanations:["Legitimate remote admin tools, like RDP or SSH, are authorized and visible, unlike a RAT which is covertly installed malware.","RDP vulnerabilities are CVEs found in Microsoft's protocol, which is a different concept from a RAT malware category.","A RAT is a Trojan that creates a hidden backdoor giving attackers persistent, covert remote control of the system.","Firewall bypass techniques use tunneling or port manipulation; a RAT instead exploits the remote access it covertly establishes, not firewalls directly."]},
  {id:257,domain:T,question:"What is a pass-the-hash attack?",options:["Sending the same request to a server multiple times","Using a captured NTLM password hash to authenticate without knowing the plaintext password","Using precomputed rainbow table lookups to reverse-engineer MD5 password hashes stolen from a compromised authentication database","Distributing the same bcrypt-hashed password value to multiple user accounts so they share identical credential representations in the directory"],answer:1,explanation:"Pass-the-hash exploits Windows NTLM: an attacker captures the hash and uses it directly to authenticate, bypassing the need for plaintext.",optionExplanations:["Replaying requests is a replay attack; pass-the-hash specifically reuses authentication hashes.","Pass-the-hash uses a captured NTLM hash as the authentication credential without needing to crack it.","Rainbow table attacks crack weak hashes to recover plaintext passwords; pass-the-hash uses the hash itself directly for NTLM authentication without needing to crack it first.","Sharing identical password hashes among accounts is a credential provisioning issue; pass-the-hash uses a stolen hash from one account to authenticate as that specific user elsewhere."]},
  {id:258,domain:T,question:"What is privilege escalation?",options:["Issuing time-limited administrative credentials to a technician to allow them to perform scheduled maintenance on specific systems","Gaining higher-level access rights than originally granted, either through exploitation or misconfiguration","Enrolling a staff member in advanced technical certification courses or professional development programs to improve their job performance","Elevating the importance of a security incident"],answer:1,explanation:"Privilege escalation exploits vulnerabilities or misconfigurations to obtain higher privileges, such as gaining admin from a standard user account.",optionExplanations:["Temporary admin access for maintenance is an authorized IAM practice; privilege escalation involves gaining elevated access through exploitation or misconfiguration, not legitimate provisioning.","Privilege escalation gains more access than originally assigned, often exploiting kernel vulnerabilities or misconfigured permissions.","Providing training is a human resources activity unrelated to security exploitation; privilege escalation is the technical act of gaining higher system access through exploitation or misconfiguration.","Incident severity escalation is an IR process step; privilege escalation is an attack technique."]},
  {id:259,domain:T,question:"Which of the following is a characteristic of a polymorphic virus?",options:["It self-replicates continuously across systems without requiring any host file at all","It encrypts all of a victim's personal files and demands a ransom payment","It is restricted to infecting only one specific type of executable file","It changes its code signature with each infection to evade detection"],answer:3,explanation:"Polymorphic malware mutates its code each replication cycle, making signature-based detection very difficult.",optionExplanations:["Self-replication without a host file defines a worm, whereas polymorphism describes code mutation to evade detection.","Encrypting files for ransom describes ransomware, a completely different malware category from polymorphism.","File-type specificity is a property some viruses share, but it is not what defines polymorphic behavior.","Polymorphic viruses alter their own code (encryption, code mutation) each time they replicate, evading signature detection."]},
  {id:260,domain:T,question:"What is a Trojan dropper?",options:["File-encrypting malware that locks all accessible data and displays a ransom demand requiring cryptocurrency payment to restore access","A Trojan that deletes files when triggered","A Trojan that steals files and sends them to a C2 server","Malware whose primary function is to install other malware on the system"],answer:3,explanation:"A dropper's purpose is to deliver and install additional malicious payloads (ransomware, RATs, backdoors) on the victim system.",optionExplanations:["Ransomware encrypts files and demands payment to restore access; a Trojan dropper is specifically designed to secretly install additional malware payloads on the compromised system.","File deletion is the function of a wiper or destructive payload; droppers deliver other malware.","Data exfiltrating Trojans are stealers; droppers install other malware rather than stealing data themselves.","A dropper is a stage-one payload whose sole job is to download and install the actual malware payload."]},
  {id:261,domain:A,question:"Which of the following is a security advantage of using private cloud over public cloud?",options:["Unlimited scalability without security concerns","No need for encryption","Greater control over the infrastructure and data isolation","Private cloud is always cheaper"],answer:2,explanation:"Private cloud gives organizations full control over their hardware, network, and data placement — important for sensitive data.",optionExplanations:["Public cloud offers greater scalability; private cloud trades some scalability for control.","Encryption is required in both private and public cloud environments.","Private cloud provides dedicated infrastructure, greater customization, and better isolation for sensitive workloads.","Private cloud typically costs more due to dedicated infrastructure; public cloud benefits from shared cost."]},
  {id:262,domain:A,question:"What is the purpose of a demilitarized zone (DMZ) in a network?",options:["Completely eliminate the need for any firewalls elsewhere on the network","Provide wireless network access to visitors and staff throughout the facility","Store the organization's most sensitive internal data in a highly protected repository","Host public-facing services between two firewalls while protecting the internal network"],answer:3,explanation:"The DMZ isolates publicly accessible servers (web, email) from the internal network using a double-firewall architecture.",optionExplanations:["DMZs work alongside firewalls and actually require at least two firewall layers to function; they do not replace firewalls.","Wireless access points are separate infrastructure entirely, while a DMZ is a network segmentation architecture.","The most sensitive data belongs in the most protected internal zone, which is the opposite of the exposed DMZ.","A DMZ places public servers between external and internal firewalls, providing buffer separation from the trusted network."]},
  {id:263,domain:A,question:"What is the purpose of a proxy auto-config (PAC) file?",options:["Allow browsers to automatically determine whether to use a proxy server for a given URL","Automatically distribute VPN gateway addresses and authentication settings to remote employee devices during VPN client software installation","Push DNS resolver addresses and search domain suffix lists to endpoints via DHCP options during IP address lease assignment","Dynamically push and apply updated firewall access control list rules to network edge devices based on current threat intelligence feeds"],answer:0,explanation:"A PAC file is a JavaScript function browsers call to decide whether to use a proxy and which one for each URL.",optionExplanations:["A PAC file defines logic for browsers to select proxy servers based on URL patterns, domains, and IP ranges.","VPN client provisioning configures remote access connectivity; a PAC file guides the browser's proxy selection logic for specific URLs, not VPN or network-level routing.","DHCP options distribute DNS and network settings; a PAC file is a JavaScript function that browsers execute to determine whether a given URL should be routed via proxy.","Dynamic firewall rule updates are threat intelligence integration; a PAC file helps browsers determine when to route requests through a proxy based on URL-matching functions."]},
  {id:264,domain:A,question:"Which cloud deployment model combines private and public cloud environments?",options:["Multi-cloud","Community cloud","Hybrid cloud","Public cloud"],answer:2,explanation:"Hybrid cloud links private and public cloud environments, enabling workloads to move between them based on needs.",optionExplanations:["Multi-cloud uses multiple public cloud providers without necessarily connecting to private infrastructure.","Community cloud is shared among organizations with similar requirements (e.g., government agencies).","Hybrid cloud integrates private cloud (or on-premises) with public cloud services through unified management.","Public cloud is entirely operated by a third-party provider with no private component."]},
  {id:265,domain:A,question:"What is the risk of using default credentials on network devices?",options:["Attackers can easily access devices because defaults are publicly known","Default credentials are permanently hardcoded into the device and can never be changed","Default credentials are actually more secure than any custom credentials an administrator could choose","Default credentials are protected using a stronger, proprietary vendor encryption scheme"],answer:0,explanation:"Default credentials (admin/admin, admin/password) are documented in vendor manuals and widely known to attackers.",optionExplanations:["Default credentials are in vendor documentation and security databases, making them trivial for attackers to exploit.","Default credentials can and must be changed; doing so is a critical first step in hardening any device.","Default credentials are weak because they are identical across every device of the same model and are publicly documented.","Default credentials have no inherent relationship to encryption strength; they are simply authentication values, often weak ones."]},
  {id:266,domain:O,question:"What is the purpose of a forensic write blocker?",options:["Apply parallel processing algorithms to compress forensic disk images and reduce the total time required to acquire large drives","Apply AES-256 encryption to completed disk images to protect their confidentiality and integrity during storage and chain-of-custody transfers","Restrict forensic analysts from duplicating, copying, or exporting any files or partition images found on evidence storage media","Allow reading storage media without any possibility of modifying it during forensic analysis"],answer:3,explanation:"A write blocker ensures forensic examination does not inadvertently alter evidence by blocking any write commands to the media.",optionExplanations:["Compression speeds up storage of images but is separate from write blocking; a write blocker's purpose is preventing modifications to source media, not accelerating image acquisition.","Encrypting acquired images protects them in transit; a write blocker is a hardware or software device that prevents any modification to the source media during the imaging process.","Preventing analysts from copying data would hinder forensic investigation; a write blocker allows unrestricted reading while specifically preventing any writes that would alter evidence.","Write blockers are hardware or software devices that intercept write commands, ensuring evidence remains unmodified during analysis."]},
  {id:267,domain:O,question:"What is the purpose of a master boot record (MBR) in forensics?",options:["A PXE-enabled network boot server that distributes operating system images to diskless workstations across the LAN on demand","A dedicated hardware security chip embedded on the motherboard that generates and stores cryptographic keys and measures platform integrity","The first sector of a storage device containing bootloader code and partition table, sometimes targeted by bootkits","A system database file that stores hashed user account passwords, group memberships, and local security policy settings for authentication"],answer:2,explanation:"The MBR is forensically significant because malware (bootkits) can hide there before the OS loads, evading most security tools.",optionExplanations:["A PXE boot server provides network-based OS deployment; the MBR is the first physical sector of a local storage device containing bootloader code and the partition table.","A hardware chip storing keys and measuring integrity describes a TPM, not the MBR; the MBR is the first disk sector holding boot code and partition table, sometimes targeted by bootkits.","The MBR is the first physical sector of a drive, containing boot instructions and partition information; bootkits infect it for persistence.","A password/policy database file describes the SAM or /etc/shadow, not the MBR; the MBR is the first sector of a storage device containing boot code and partition information."]},
  {id:268,domain:O,question:"What is the MITRE ATT&CK framework?",options:["A software development methodology that integrates security requirements and code review checkpoints throughout each phase of the development lifecycle","A regulatory compliance standard specifying mandatory cybersecurity controls for banks and financial services firms under federal oversight","A knowledge base of adversary tactics, techniques, and procedures (TTPs) based on real-world observations","A standardized document template providing step-by-step guidance for security teams responding to common incident categories"],answer:2,explanation:"MITRE ATT&CK catalogs attacker TTPs organized by attack lifecycle stages, used for threat hunting, detection, and red team planning.",optionExplanations:["Integrating security into development describes DevSecOps or SDLC security practices; MITRE ATT&CK catalogs attacker behaviors observed in real incidents, not development methodologies.","Regulatory standards for financial institutions include PCI DSS or GLBA; MITRE ATT&CK is a non-regulatory knowledge base of real-world adversary tactics, techniques, and procedures.","MITRE ATT&CK documents real-world adversary behaviors organized into tactics (goals) and techniques (methods).","Step-by-step incident guidance describes a runbook or playbook; MITRE ATT&CK is a threat intelligence knowledge base cataloging attacker TTPs based on real-world observation."]},
  {id:269,domain:O,question:"What is the Cyber Kill Chain?",options:["A regulatory compliance audit checklist that helps organizations validate adherence to mandatory security controls and reporting requirements","Lockheed Martin's model describing the stages of a cyberattack from reconnaissance to exfiltration","A network architecture design model that divides infrastructure into isolated security zones separated by firewalls and access controls","A vendor risk management methodology for systematically assessing and securing third-party supplier and software supply chain relationships"],answer:1,explanation:"The Cyber Kill Chain models attacks in 7 stages: Reconnaissance, Weaponization, Delivery, Exploitation, Installation, C2, Actions on Objectives.",optionExplanations:["A compliance checklist validates regulatory control adherence; the Cyber Kill Chain is a threat modeling framework describing attack progression stages, not a compliance validation tool.","The Cyber Kill Chain (Lockheed Martin) describes the sequential stages attackers follow, enabling defenders to break the chain.","Network segmentation models define zone-based architecture; the Cyber Kill Chain is a sequential attack lifecycle model describing how adversaries progress from reconnaissance to their objectives.","Supply chain risk management addresses third-party vendor risk; the Cyber Kill Chain is Lockheed Martin's model describing the sequential stages of a cyberattack from start to exfiltration."]},
  {id:270,domain:O,question:"What is the difference between MTTD and MTTR?",options:["MTTD is the mean time to detect a threat; MTTR is the mean time to repair/recover","MTTD quantifies how quickly a failed system is fully restored to operational status; MTTR measures how rapidly security threats are first detected","MTTD and MTTR are identical and interchangeable performance metrics both measuring the speed of incident detection and remediation","Both MTTD and MTTR calculate the average interval of time elapsed between consecutive security incidents affecting the same organizational systems"],answer:0,explanation:"MTTD measures how long it takes to detect a threat; MTTR measures how long to recover. Both are key SOC performance metrics.",optionExplanations:["MTTD (Mean Time to Detect) and MTTR (Mean Time to Repair/Respond) are distinct metrics measuring detection and recovery speed.","This reverses the definitions; MTTD measures time to detect a threat, while MTTR measures the time to repair or recover from an incident after it has been detected.","They are not identical; MTTD (Mean Time To Detect) measures how long before a threat is identified, while MTTR (Mean Time To Repair) measures how long restoration takes.","Neither metric measures time between incidents; MTTD measures detection latency for individual threats, and MTTR measures the recovery duration for individual incidents."]},
  {id:271,domain:P,question:"What is the purpose of a gap analysis in security?",options:["Deliver targeted security awareness training sessions addressing specific knowledge gaps found during an employee phishing simulation assessment","Compare current security posture against a target standard to identify what needs improvement","Use automated scanning tools to probe all network-connected hosts and enumerate services listening on accessible TCP and UDP ports","Run automated endpoint detection tools to identify and classify malicious software present on organizational computing assets"],answer:1,explanation:"A gap analysis identifies the difference between the current state of security and a desired target state (framework, standard, or regulation).",optionExplanations:["Training staff addresses identified weaknesses; a gap analysis is the structured process of comparing current state to a target standard, not the remediation activity that follows it.","A gap analysis systematically compares current controls against required controls, identifying what is missing or insufficient.","Port scanning discovers exposed network services; a gap analysis compares the organization's existing security capabilities against a framework or target maturity level to find shortfalls.","Scanning for malware is a threat detection activity; a gap analysis compares current security posture against a target standard to identify areas requiring investment or improvement."]},
  {id:272,domain:P,question:"Which framework is specifically designed for securing industrial control systems (ICS)?",options:["NIST CSF","ISO 27001","PCI DSS","NERC CIP"],answer:3,explanation:"NERC CIP (North American Electric Reliability Corporation Critical Infrastructure Protection) standards apply to bulk electric system security.",optionExplanations:["NIST CSF is a general cybersecurity framework applicable to all sectors.","ISO 27001 is a general information security management standard, not specific to ICS.","PCI DSS applies to payment card data environments, not industrial control systems.","NERC CIP is specifically designed for protecting the bulk power system and electric utilities from cybersecurity threats."]},
  {id:273,domain:P,question:"What is a penetration testing scope document?",options:["A formal findings report produced after testing that catalogs all security vulnerabilities discovered, rated by exploitability and severity","A remediation roadmap document prioritizing recommended security improvements and fixes identified during the completed assessment engagement","A written agreement defining the boundaries, targets, and rules of engagement for a pen test","A technical setup guide explaining how to install, configure, and calibrate scanning and exploitation tools before beginning a security assessment"],answer:2,explanation:"The scope document (rules of engagement) defines what can be tested, which methods are permitted, and the testing timeline.",optionExplanations:["A findings report documents discovered issues; the scope document is created before testing begins and defines the boundaries, authorized targets, and rules of engagement for the engagement.","A remediation roadmap addresses findings after the test; the scope document is a pre-engagement agreement defining what systems may be tested and what techniques are authorized.","A scope document defines boundaries, IP ranges, allowed techniques, contact information, and the test window.","A tool configuration guide is an operational reference; the scope document is a legal agreement defining the authorized boundaries, objectives, and rules of engagement for the test."]},
  {id:274,domain:P,question:"What is the purpose of a vulnerability disclosure policy?",options:["Define how the organization wants to receive, process, and respond to security vulnerability reports from researchers","Establish a financial incentive program that rewards security researchers with monetary bounties for every confirmed vulnerability they report","Configure automated patch management systems to deploy remediation for every discovered vulnerability within 24 hours of initial detection","Require all external parties to sign legal non-disclosure agreements before any security vulnerability information may be shared with the organization"],answer:0,explanation:"A VDP sets expectations for responsible disclosure, encouraging researchers to report vulnerabilities safely without legal fear.",optionExplanations:["A VDP establishes a clear process for researchers to report vulnerabilities, promising legal protection and response timelines.","A bug bounty program is one specific mechanism for receiving reports; a vulnerability disclosure policy is a broader framework defining how all vulnerability reports are received and processed.","Automated patching timelines are a patch management policy; a vulnerability disclosure policy defines how researchers should submit findings and how the organization will communicate and respond.","NDAs are legal instruments, not a disclosure policy; a vulnerability disclosure policy defines the process for receiving, triaging, and responding to vulnerability reports from external researchers."]},
  {id:275,domain:P,question:"What is a memorandum of understanding (MOU) in security context?",options:["A detailed technical configuration document specifying exact system and network settings","A fully binding legal contract enforceable in court between two separate organizations","An itemized vendor invoice listing charges for delivered security consulting services","A non-binding agreement establishing shared understanding of security responsibilities between parties"],answer:3,explanation:"An MOU documents mutual understanding and expectations, often used before a formal contract or for partner security agreements.",optionExplanations:["Technical configuration documents specify system settings, while an MOU instead defines organizational relationships and expectations.","A legally binding contract carries formal legal remedies, whereas an MOU is typically non-binding by design.","Invoices are financial billing documents, entirely distinct from an MOU's role of defining a relationship and expectations.","An MOU establishes mutual expectations between parties without full legal enforceability, often used to formalize partnerships."]},
  {id:276,domain:G,question:"What is the difference between synchronous and asynchronous encryption?",options:["Synchronous encryption uses a shared clock signal synchronized between sender and receiver, while asynchronous encryption transmits data with start and stop framing bits","Synchronous and asynchronous encryption are interchangeable terms both describing symmetric block cipher algorithms that operate on fixed-length data blocks","Asynchronous encryption consistently achieves higher throughput and performance than synchronous algorithms by eliminating the need for keystream clock synchronization","Synchronous encryption refers to stream ciphers that operate in sync with a clock/keystream; asynchronous is not a standard cryptographic term"],answer:3,explanation:"In some contexts, synchronous stream ciphers maintain an independent keystream; 'asynchronous' is not standard terminology in cryptography.",optionExplanations:["This conflates data transmission terminology with cryptographic modes; synchronous in cryptography refers to stream ciphers tied to a keystream, not clock signaling between parties.","They are not interchangeable standard terms; synchronous refers to stream ciphers synchronized with a keystream, while asynchronous is not a recognized standard cryptographic classification.","Asynchronous is not a standard cryptographic performance category; performance differences exist between stream and block ciphers, but asynchronous encryption is not a recognized cryptographic term.","Synchronous stream ciphers generate keystreams independently; asynchronous is not a standardized cryptographic term."]},
  {id:277,domain:G,question:"What is the purpose of a TPM (Trusted Platform Module)?",options:["A hardware chip that stores cryptographic keys and enables platform integrity measurement","Protect data transmitted between client devices and network gateways using TLS encryption negotiated through a security appliance","Authenticate remote network users through RADIUS or TACACS+ challenge-response protocols managed by a centralized network access server","Scan fingerprints or capture facial geometry to verify user identity through biometric authentication before granting system access"],answer:0,explanation:"A TPM securely stores encryption keys, performs cryptographic operations, and attests to the integrity of the boot process.",optionExplanations:["The TPM is a dedicated security chip providing secure key storage, random number generation, and secure boot attestation.","TLS encryption protects network traffic using software protocols; a TPM is a hardware chip that stores cryptographic keys and measures system integrity at the platform level.","RADIUS/TACACS+ provide network authentication via dedicated servers; a TPM is a local hardware chip on the device itself that stores keys and provides platform integrity measurement.","Biometric readers are user verification sensors; a TPM is a hardware security chip that stores keys and measures platform integrity to detect boot-level tampering, not identify users biometrically."]},
  {id:278,domain:G,question:"Which type of encryption is used in HTTPS for the initial key exchange?",options:["Asymmetric encryption","No encryption during handshake","Symmetric encryption","Hashing"],answer:0,explanation:"TLS uses asymmetric encryption (RSA or ECDHE) during the handshake to securely exchange the symmetric session key.",optionExplanations:["Asymmetric encryption (or key agreement) establishes the shared symmetric session key during the TLS handshake.","TLS always encrypts the handshake parameters; the entire session is encrypted.","Symmetric encryption is used after the handshake for bulk data; asymmetric secures the key exchange.","Hashing provides integrity (HMAC) in TLS; it does not establish the session key."]},
  {id:279,domain:G,question:"What is a supplicant in 802.1X authentication?",options:["The certificate authority issuing client certificates","The switch or AP that forwards authentication traffic","The RADIUS server that authenticates users","The client device requesting network access"],answer:3,explanation:"In 802.1X, the supplicant is the client (user's device) requesting access; the authenticator is the switch/AP; the auth server is RADIUS.",optionExplanations:["The CA issues certificates used by the supplicant and auth server; it is not a role in the 802.1X exchange.","The switch or wireless AP is the authenticator (the middle component), not the supplicant.","The RADIUS server is the authentication server, not the supplicant.","The supplicant is the client device requesting network access through the 802.1X framework."]},
  {id:280,domain:G,question:"What is a session key?",options:["A long-term permanent encryption key kept securely stored inside a hardware security module","The long-term private key that is permanently bound to a PKI certificate","A temporary symmetric key created for a single communication session","A dedicated signing key used exclusively by a CA to sign digital certificates"],answer:2,explanation:"Session keys are ephemeral symmetric keys negotiated for each session, providing both speed (symmetric) and forward secrecy (temporary).",optionExplanations:["Permanent keys stored in HSMs are long-term keys meant to persist, unlike the short-lived nature of a session key.","A PKI private key is the long-term asymmetric key tied to an identity, while a session key is symmetric and ephemeral.","A session key is a temporary symmetric key generated fresh for each session, ensuring efficient encryption and forward secrecy.","Certificate signing uses the CA's long-term private key, whereas a session key is used to encrypt the session's actual data."]},
  {id:281,domain:T,question:"What is an ARP spoofing attack?",options:["Sending fake ARP messages to associate the attacker's MAC address with a legitimate IP","Impersonating a legitimate DHCP server to hand out malicious network configuration settings","Intercepting DNS queries in transit and returning forged responses to redirect victims","Flooding a switch's address table with an overwhelming volume of fake MAC addresses"],answer:0,explanation:"ARP spoofing poisons ARP caches on the LAN so traffic destined for a legitimate IP is sent to the attacker's MAC address.",optionExplanations:["ARP spoofing sends gratuitous ARP replies linking the attacker's MAC to a victim's IP, enabling traffic interception.","Impersonating a DHCP server describes a DHCP spoofing attack, a related but separate LAN attack from ARP spoofing.","Intercepting DNS queries and returning forged responses describes DNS spoofing, a different attack from ARP spoofing.","Flooding a switch's MAC table describes a MAC flooding attack, which forces the switch into hub-like broadcast mode, a distinct technique from ARP spoofing."]},
  {id:282,domain:T,question:"What is a MAC flooding attack?",options:["Intercepting and replaying wireless MAC-based authentication handshakes to gain network access","Spoofing a single trusted MAC address to bypass port-based authentication controls","Sending malicious executable payloads embedded directly within crafted network packets","Overwhelming a switch's MAC address table to force it to broadcast all frames"],answer:3,explanation:"MAC flooding exhausts the CAM table, causing the switch to flood all traffic to all ports like a hub, enabling eavesdropping.",optionExplanations:["Intercepting wireless MAC authentication targets Wi-Fi access control, whereas MAC flooding specifically targets a wired switch's CAM table.","Spoofing a single MAC address to bypass authentication is a targeted impersonation technique, distinct from overwhelming the switch's entire table.","Delivering malware through network packets is a different delivery mechanism entirely from overwhelming a switch's address table.","MAC flooding sends massive quantities of frames with fake MACs, filling the CAM table and causing the switch to forward all traffic to all ports."]},
  {id:283,domain:T,question:"What is DHCP spoofing?",options:["Deliberately blocking all DHCP traffic at the network perimeter using explicitly configured firewall and access control rules","Flooding the legitimate DHCP server with an overwhelming volume of bogus lease requests until its address pool is exhausted","Passively scanning the local network segment to discover and catalog all currently active DHCP servers present","An attacker acting as a rogue DHCP server to assign clients false network settings including a malicious gateway"],answer:3,explanation:"A rogue DHCP server assigns attacker-controlled gateway IPs, routing all client traffic through the attacker.",optionExplanations:["Blocking DHCP traffic is a defensive firewall or DHCP snooping function, not an attack technique like spoofing.","Flooding the DHCP server with requests describes a DHCP starvation attack, which exhausts the address pool rather than serving false configuration.","Scanning for DHCP servers is passive reconnaissance, a precursor activity distinct from actually spoofing DHCP responses.","A rogue DHCP server assigns attacker-controlled gateway IPs, routing all client traffic through the attacker."]},
  {id:284,domain:T,question:"What is an SSL stripping attack?",options:["Swapping a website's legitimate SSL certificate for an attacker-generated self-signed certificate to impersonate the domain","Physically removing or deleting the installed SSL/TLS certificate files from a web server's configuration directory","Extracting an organization's SSL private keys from a compromised server to decrypt previously captured traffic","Downgrading an HTTPS connection to HTTP by intercepting the initial redirect"],answer:3,explanation:"SSL stripping intercepts the HTTP-to-HTTPS redirect and maintains an unencrypted connection with the victim while HTTPS is used with the server.",optionExplanations:["Presenting a fraudulent self-signed certificate is a separate man-in-the-middle technique that typically triggers browser warnings; SSL stripping avoids certificates altogether by keeping the victim on unencrypted HTTP.","Deleting certificate files from a server would simply break HTTPS entirely rather than covertly intercept traffic; SSL stripping is an active man-in-the-middle interception technique instead.","Obtaining private keys is a PKI compromise aimed at decrypting stored or intercepted data; SSL stripping instead manipulates the connection in real time without needing any keys.","SSL stripping intercepts the HTTP redirect to HTTPS, maintaining unencrypted communication with the victim while connecting to the server via HTTPS."]},
  {id:285,domain:T,question:"Which of the following BEST describes a cross-site scripting (XSS) attack?",options:["Injecting malicious scripts into web pages that execute in other users' browsers","Inserting unauthorized SQL commands into web form input fields to manipulate or extract data from a backend database","Exploiting a buffer overflow vulnerability in a web server's memory handling to execute arbitrary attacker-supplied code","Silently intercepting and reading network traffic exchanged between two web servers during a backend transaction"],answer:0,explanation:"XSS injects client-side scripts (JavaScript) into pages served to other users, executing in their browser's security context.",optionExplanations:["XSS embeds malicious JavaScript into web pages, executing in victims' browsers to steal cookies, redirect, or perform actions.","SQL injection manipulates backend database queries through form inputs; XSS instead targets the victim's browser by injecting executable script content.","Buffer overflow attacks corrupt server memory to hijack program execution; XSS instead abuses a web page's trust to run scripts in visiting users' browsers.","Intercepting server-to-server traffic describes a man-in-the-middle attack at the network layer; XSS is a client-side injection attack delivered through a web application."]},
  {id:286,domain:A,question:"What is a security zone in network architecture?",options:["A physical geographic area within a facility where surveillance cameras and guards are stationed to monitor for intruders","A dedicated VLAN configured exclusively to host vulnerability scanners, SIEM collectors, and other security management tools","A single subnet reserved only for publicly-facing DMZ servers, separate from any other trust-based network division","A defined network segment with specific trust level and associated security controls"],answer:3,explanation:"Security zones partition the network by trust level (trusted, untrusted, DMZ) and apply appropriate controls at zone boundaries.",optionExplanations:["Camera-monitored areas describe physical security zones for guarding facilities; a network security zone is a logical trust boundary within the IT architecture.","A management VLAN for security tooling is a configuration detail addressing where tools live; a security zone is the broader architectural concept of trust-based segmentation.","The DMZ is only one example of a security zone; other zones include trusted internal networks, untrusted external networks, and partner-facing segments.","Security zones define trust levels for network segments with firewalls and controls enforced at zone boundaries."]},
  {id:287,domain:A,question:"What is the purpose of subnetting in network security?",options:["Automatically assign unique hardware MAC addresses to newly connected devices joining the local network","Boost overall network throughput and reduce latency by upgrading switch hardware and cabling infrastructure","Provide wireless connectivity to end-user devices through strategically placed access points across a building","Divide a large network into smaller, more manageable and isolated segments"],answer:3,explanation:"Subnetting creates smaller network segments that limit broadcast domains and can restrict traffic flow between segments.",optionExplanations:["MAC addresses are permanently burned into network interface hardware at the factory; subnetting operates at Layer 3 with IP addresses, not Layer 2 hardware addresses.","Subnetting doesn't inherently increase throughput or reduce latency; those gains come from hardware upgrades, while subnetting improves manageability and security through isolation.","Wireless connectivity is delivered by access points and radio infrastructure; subnetting is an IP addressing scheme used to segment any network, wired or wireless.","Subnetting divides large IP address spaces into smaller segments, reducing broadcast domains and enabling traffic control."]},
  {id:288,domain:A,question:"What is the role of an HSM in a PKI?",options:["Directly issue signed digital certificates to end users and validate their identity information before approval","Publish updated revocation status for compromised or expired certificates to relying parties across the organization","Securely generate and store the CA's private key, protecting it from extraction","Provide a self-service web portal where end users can submit and track their certificate requests"],answer:2,explanation:"An HSM stores the CA's private key in tamper-resistant hardware, ensuring it cannot be extracted even if the CA server is compromised.",optionExplanations:["Issuing certificates and validating identity is the CA software's function; the HSM's job is only to safeguard the private key used to sign what the CA issues.","Publishing revocation status is managed by the CA through CRLs and OCSP responders; the HSM's role is limited to protecting the signing key itself.","An HSM provides hardware protection for the CA's private key, making it resistant to extraction and software-based attacks.","A self-service request portal is a CA application's user-facing interface; the HSM operates behind the scenes protecting cryptographic key material, not handling user requests."]},
  {id:289,domain:A,question:"What is meant by 'resilience' in security architecture?",options:["Deploying multiple duplicate security tools and vendors so that no single product failure creates a gap","The ability to continue operating and recover quickly despite attacks, failures, or disasters","The capability to block and stop every possible attack before it can reach or affect any system","Maintaining the highest-performance hardware and software so that systems process transactions as fast as possible"],answer:1,explanation:"Security resilience means systems can withstand or recover from disruptions without unacceptable loss of functionality.",optionExplanations:["Redundant tools can contribute to resilience but are only one tactic among many, not a complete definition of the broader concept.","Resilience is the capacity to absorb disruptions, maintain essential functions, and recover with minimal impact.","No architecture can realistically prevent every attack; resilience is instead about surviving and recovering from the ones that do get through.","Raw processing speed is a performance goal unrelated to surviving disruptions; resilience is about continuity and recovery, not velocity."]},
  {id:290,domain:A,question:"What is the purpose of a web application firewall (WAF)?",options:["Provide and manage SSL/TLS certificate-based encryption for incoming connections to a web server","Filter and block network packets purely based on Layer 3 IP addresses and Layer 4 port numbers","Inspect and filter HTTP/S traffic to protect web applications from attacks like SQLi and XSS","Continuously monitor server CPU, memory, and disk performance metrics to alert on resource exhaustion"],answer:2,explanation:"A WAF analyzes HTTP/S requests and responses against security policies to block web application attacks.",optionExplanations:["TLS certificate encryption is handled by the web server or load balancer's own configuration; a WAF may perform TLS offloading but its purpose is attack inspection.","Layer 3/4 filtering by IP address and port is performed by traditional network firewalls; a WAF instead inspects Layer 7 application content.","WAFs inspect HTTP application traffic, detecting and blocking OWASP Top 10 attacks including SQLi, XSS, and CSRF.","Performance monitoring of CPU, memory, and disk is handled by dedicated APM tools; a WAF's focus is security inspection of application traffic, not resource metrics."]},
  {id:291,domain:O,question:"What is the concept of 'dwell time' in security?",options:["The scheduled length of time allotted for a compliance team to complete a formal security audit","The amount of time a security analyst spends triaging, researching, and investigating a single generated alert","The length of time an attacker remains undetected inside a network after compromising it","The total elapsed time required to fully restore affected systems and services back to normal operation"],answer:2,explanation:"Dwell time (breakout time) is how long attackers lurk undetected; reducing it is a key goal of threat hunting and detection.",optionExplanations:["Audit duration is a scheduling and planning parameter for compliance reviews; dwell time is a threat-detection metric about undiscovered attacker presence.","Time spent by an analyst investigating an alert relates to workload and MTTR metrics; dwell time instead measures attacker persistence before any detection occurs.","Dwell time measures how long an attacker has been inside the network without being detected — a key indicator of detection effectiveness.","Recovery duration is measured by metrics like MTTR after an incident is discovered; dwell time is the pre-detection period the attacker went unnoticed."]},
  {id:292,domain:O,question:"What is the purpose of threat modeling?",options:["Deploy and configure network firewalls with rule sets derived from a completed risk assessment","Provide developers with structured, ongoing training courses covering secure coding practices and common vulnerabilities","Identify and prioritize potential threats against a system or application during the design phase","Automatically scan live production systems for known vulnerabilities using an authenticated network vulnerability scanner"],answer:2,explanation:"Threat modeling (STRIDE, PASTA, LINDDUN) systematically identifies threats early in design to guide security controls.",optionExplanations:["Firewall deployment is one possible outcome that might result from threat model findings; the threat model itself is the earlier analysis process, not the control.","Secure coding training is a security education activity for developers; threat modeling is a structured analytical methodology for identifying design-level threats.","Threat modeling analyzes potential adversaries, threats, and weaknesses during design to enable proactive security controls.","Vulnerability scanning tests already-built, live systems for known flaws; threat modeling is a proactive design-time analysis activity performed before code is written."]},
  {id:293,domain:O,question:"What is the purpose of a security kernel?",options:["The central cryptographic processing component embedded within a dedicated hardware security module appliance","A minimal, trusted portion of an OS that implements and enforces all security policies","A dedicated physical server configured to run a suite of centralized security monitoring tools","A previously undiscovered software flaw or vulnerability residing deep within the operating system's kernel code"],answer:1,explanation:"A security kernel is the smallest, most trusted portion of an OS — typically the TCB — that enforces all access control decisions.",optionExplanations:["HSM cryptographic components are hardware appliances for key protection, not what security professionals call a security kernel, which is an OS design concept.","The security kernel is the trusted core of an OS that implements mandatory security policies and cannot be bypassed.","A dedicated security server is simply hardware running security software; a security kernel is a conceptual, trusted core built into the operating system itself.","A kernel vulnerability is a specific coding flaw or CVE within OS code; a security kernel is instead an architectural concept describing the trusted enforcement core."]},
  {id:294,domain:O,question:"What is the difference between active and passive vulnerability scanning?",options:["Active scanning consistently uncovers a greater total number of vulnerabilities than passive scanning is capable of finding","Passive scanning is highly invasive to monitored systems, while active scanning never touches or affects any target system","Active scanning probes systems directly; passive scanning analyzes captured network traffic without direct probing","Active scans always require manual analyst execution step by step; passive scans instead run fully automated on a schedule"],answer:2,explanation:"Active scanning sends probes to systems; passive scanning observes traffic to infer vulnerabilities without touching target systems.",optionExplanations:["Both scanning types can uncover significant vulnerabilities; which finds more depends on scope and target visibility, not an inherent property of the method.","The reality is reversed: active scanning directly probes and can disrupt systems, making it more invasive, while passive scanning only observes traffic non-intrusively.","Active scanning directly queries systems (Nessus, OpenVAS); passive scanning observes traffic without touching targets.","Both active and passive scanning can be run manually or automated on a schedule; the manual-versus-automated distinction doesn't define the two approaches."]},
  {id:295,domain:O,question:"What is a vulnerability scoring system (CVSS)?",options:["An active scanning tool that probes network hosts and applications to discover exploitable vulnerabilities","A centralized repository tracking vendor-issued patch releases, version numbers, and update deployment schedules","A comprehensive, continuously updated catalog listing every publicly disclosed Common Vulnerabilities and Exposures identifier","A standardized framework for rating the severity of vulnerabilities using metrics like exploitability and impact"],answer:3,explanation:"CVSS (Common Vulnerability Scoring System) provides 0-10 severity scores based on exploitability, scope, and impact metrics.",optionExplanations:["Scanning tools such as Nessus discover vulnerabilities and report their CVSS scores; CVSS itself is the scoring standard, not the scanning software.","A vendor patch database tracks available fixes and release timing; CVSS instead scores how severe the underlying vulnerabilities those patches address actually are.","The CVE list catalogs individual vulnerabilities by identifier; CVSS is the separate scoring system used to rate how severe each one is.","CVSS assigns a numeric severity score based on factors like attack vector, complexity, privileges required, and impact."]},
  {id:296,domain:P,question:"What is a system security plan (SSP)?",options:["A document outlining the test cases and methodology used to verify software quality before release","A formal document describing a system's security requirements, controls, and their implementation","A step-by-step procedure describing how backups are restored following a system or data failure","A recurring schedule listing which systems the SOC team monitors and reviews on a daily basis"],answer:1,explanation:"An SSP (required by NIST and FISMA) documents a system's security environment, control implementations, and responsibilities.",optionExplanations:["A software test plan documents functional and quality testing approaches; an SSP instead documents the security controls implemented and operating on a system.","An SSP documents security controls implemented on a system, their status, responsible parties, and operational environment.","A backup recovery procedure is a disaster recovery document focused on restoring data; an SSP is a broader security documentation requirement covering all controls.","A daily monitoring schedule is an operational task list for the SOC; an SSP is a comprehensive documentation artifact describing security control implementation."]},
  {id:297,domain:P,question:"What is the purpose of an audit trail in security?",options:["Actively block unauthorized users from gaining entry to protected systems and sensitive data resources","Automatically trigger predefined remediation actions the instant a suspicious security event is detected","A chronological record of events and actions enabling accountability and forensic investigation","Apply strong encryption algorithms to activity logs so their contents remain confidential at rest"],answer:2,explanation:"An audit trail is an immutable log of events providing accountability, supporting investigations and demonstrating compliance.",optionExplanations:["Blocking unauthorized access is the function of access controls like authentication and authorization; an audit trail instead records what happened after the fact.","Automated response to events describes SOAR playbooks; audit trails are the evidentiary record consulted to inform and justify that response.","An audit trail records who did what, when, and from where — providing accountability and forensic reconstruction.","Encrypting logs is a protective control applied to the audit trail's storage; the trail itself is the chronological record of activity, not an encryption mechanism."]},
  {id:298,domain:P,question:"What is the concept of 'privacy by design'?",options:["Conducting a formal, scheduled review of privacy compliance and controls once every calendar year","Bolting privacy controls onto an already-completed system only after it has been fully built and deployed","Applying strong encryption uniformly to every piece of personal data an organization collects or stores","Incorporating privacy protections into systems from the initial design phase rather than as an afterthought"],answer:3,explanation:"Privacy by design (Ann Cavoukian) integrates privacy as a core requirement from the start, not bolted on later.",optionExplanations:["An annual audit is a periodic compliance verification exercise; privacy by design instead is about proactively embedding privacy continuously from the earliest design stage.","Retrofitting privacy controls after a system is already built is what privacy by design specifically seeks to avoid, since it is less effective than building it in from the start.","Encryption is just one specific technical control that supports privacy; privacy by design is a much broader design philosophy encompassing data minimization and purpose limitation too.","Privacy by design embeds privacy principles (data minimization, purpose limitation) into architecture from the beginning."]},
  {id:299,domain:P,question:"What does the term 'data sovereignty' mean?",options:["A legal right granting any individual unrestricted access to any data published anywhere on the public internet","Data is subject to the laws and governance of the country where it is stored or processed","A legal doctrine stating that organizations automatically own outright all data they collect from customers or users","A universal technical requirement mandating that all data be encrypted identically no matter where it physically resides"],answer:1,explanation:"Data sovereignty means data stored in a country is subject to that country's laws, affecting where organizations can store data.",optionExplanations:["Unrestricted internet access rights are an unrelated concept from digital rights discussions; data sovereignty specifically concerns which country's laws govern stored data.","Data sovereignty recognizes that data stored in a country falls under that nation's legal jurisdiction and regulations.","Data ownership rights actually depend on contracts, privacy law, and data subject rights rather than being automatic; data sovereignty is instead about legal jurisdiction over storage location.","Encryption requirements vary widely by regulation and industry rather than being universal; data sovereignty concerns jurisdictional legal control, not a specific encryption mandate."]},
  {id:300,domain:P,question:"What is a security charter?",options:["A document specifying the technical rules and standards governing network traffic and device configuration","A signed legal document authorizing a specific penetration test engagement and defining its testing boundaries","A detailed technical configuration listing the specific access permissions and rules enforced by firewalls","A document defining the authority, scope, responsibilities, and goals of the security program"],answer:3,explanation:"A security charter grants the CISO and security program formal authority, defines scope, and establishes organizational accountability.",optionExplanations:["A network security policy defines specific technical rules to follow; a charter establishes the underlying authority to create and enforce policies like it.","Pen test authorization is a rules-of-engagement document scoped to one testing engagement; a charter is a much broader mandate for the entire security program.","Firewall rule sets are technical access control configurations enforced at the network perimeter; a charter instead establishes the security program's organizational authority.","A security charter formalizes the security program's mandate, authority, and responsibilities within the organization."]},
  {id:301,domain:G,question:"What is the purpose of a time-based one-time password (TOTP)?",options:["Securely store and synchronize a user's saved account passwords across multiple cloud-connected devices","Generate a short-lived password based on the current time and a shared secret, valid for ~30 seconds","Allow a user to authenticate once and gain access to multiple connected applications and services","Completely eliminate the need for passwords, biometrics, or any other authentication factor across every system"],answer:1,explanation:"TOTP (RFC 6238) generates a new 6-digit code every 30 seconds using HMAC-SHA1 and the current timestamp.",optionExplanations:["Cloud password storage and synchronization is the function of a password manager or vault; TOTP instead generates temporary numeric codes for verification.","TOTP combines the current Unix time with a shared secret using HMAC to generate a short-lived code.","Single sign-on lets one login grant access across multiple systems, which is a separate federation concept; TOTP is a single authentication factor used for verification.","TOTP is typically deployed as an additional second factor alongside a password, not as a wholesale replacement for every authentication method in use."]},
  {id:302,domain:G,question:"Which of the following BEST describes a hardware OTP token?",options:["A smart card embedding a private key certificate used to digitally sign documents and emails","A physical device that generates one-time passwords without requiring network connectivity","A portable USB storage drive that saves a user's plaintext passwords in an encrypted file","A biometric scanning device that captures and matches a user's unique fingerprint pattern"],answer:1,explanation:"Hardware tokens (RSA SecurID, YubiKey OTP) generate time or counter-based OTPs without network or battery in some models.",optionExplanations:["Smart cards store digital certificates and private keys used for signing operations; OTP tokens instead generate short numeric codes without any certificate involved.","Hardware OTP tokens are self-contained devices generating fresh codes for each authentication, independent of network access.","A USB drive is passive file storage for saved credentials; a hardware OTP token instead actively generates a new dynamic code for each login.","A fingerprint reader captures biometric data as an inherence factor; an OTP token is a possession factor that produces time-based numeric codes."]},
  {id:303,domain:T,question:"What is a golden ticket attack in Active Directory?",options:["Physically breaking into a data center to gain hands-on access to unlocked domain controller hardware","Injecting malicious query syntax into LDAP directory lookups to bypass authentication or extract directory data","Forging a Kerberos TGT using the KRBTGT account hash, granting access to any resource in the domain","Sending fraudulent emails impersonating Microsoft support to trick users into revealing their account credentials"],answer:2,explanation:"By compromising the KRBTGT hash, attackers create forged TGTs valid for any account and resource, granting domain-wide persistence.",optionExplanations:["Physically breaching a data center is a distinct facility-security attack; a golden ticket is instead a purely logical forgery of an authentication token.","LDAP injection manipulates directory service queries through unsanitized input; a golden ticket instead exploits the Kerberos ticket-granting process using a stolen hash.","A golden ticket is a forged Kerberos TGT created with the KRBTGT account's NTLM hash, granting unlimited domain access.","Microsoft-themed phishing emails are a social engineering technique for credential theft, unrelated to forging Kerberos tickets."]},
  {id:304,domain:T,question:"What is a silver ticket attack?",options:["Extracting cached NTLM password hashes directly from a compromised system's volatile process memory","Forging a Kerberos service ticket for a specific service without contacting the KDC","A weakened variant of a golden ticket that still grants domain-wide access but for a shorter validity window","Capturing and resending a previously observed valid Kerberos authentication exchange to impersonate the original sender"],answer:1,explanation:"Silver tickets forge Kerberos service tickets using a service account's hash, granting access to a specific service without KDC involvement.",optionExplanations:["Stealing NTLM hashes from memory is a credential-harvesting technique; a silver ticket instead uses an already-obtained service account hash to forge a ticket directly.","Silver tickets forge Kerberos service tickets using a service account's hash, granting access to a specific service without KDC involvement.","A silver ticket is related conceptually to a golden ticket but is fundamentally different: it targets one specific service rather than being a scoped-down version of domain-wide access.","A replay attack reuses captured authentication traffic verbatim; a silver ticket is instead freshly forged from scratch using a stolen account hash."]},
  {id:305,domain:T,question:"What is lateral movement in a cyberattack?",options:["Transferring stolen sensitive data from the compromised network out to an attacker-controlled external server","Obtaining higher-level administrative privileges on the single initially compromised host machine itself","Spreading from the initial compromised system to other systems within the network","Increasing the volume and speed of network traffic generated during a denial-of-service flooding attack"],answer:2,explanation:"Lateral movement uses techniques like pass-the-hash, RDP, and SSH to move from the beachhead to other targets in the network.",optionExplanations:["Data exfiltration is typically the attacker's final objective; lateral movement is the earlier technique used to reach valuable targets before any data leaves the network.","Privilege escalation raises access on one already-compromised system; lateral movement instead spreads the attacker's foothold across additional systems in the network.","Lateral movement expands the attacker's foothold across the network from the initial compromised system.","Bandwidth relates to network capacity consumed by traffic, most relevant to DoS attacks; lateral movement is instead a technique for expanding attacker access across hosts."]},
  {id:306,domain:A,question:"What is micro-segmentation and how does it differ from traditional segmentation?",options:["Micro-segmentation simply configures smaller VLAN subnets, while traditional segmentation always uses larger, broader VLAN ranges","Micro-segmentation and traditional segmentation describe the exact same network isolation approach implemented at identical granularity","Micro-segmentation applies policies at the individual workload level; traditional uses zone-level segmentation with firewalls","Traditional segmentation is implemented entirely through software-defined controls, while micro-segmentation instead requires dedicated physical hardware appliances"],answer:2,explanation:"Micro-segmentation enforces policies per workload/VM using software-defined controls, much more granular than VLAN-based zone segmentation.",optionExplanations:["VLAN size is not what distinguishes the two approaches; the real difference is the granularity level at which security policy is enforced.","They address the same underlying goal of isolation but do so at very different levels of granularity, so they are not the same concept.","Micro-segmentation applies security policies to individual workloads or containers, limiting east-west movement far more granularly than traditional zones.","The reality is closer to the opposite: micro-segmentation is typically software-defined and doesn't require dedicated hardware per workload, unlike some traditional appliance-based approaches."]},
  {id:307,domain:A,question:"What security concern is associated with shadow IT?",options:["Legitimate security monitoring software installed and running without the required formal management approval process","IT department staff members working extra unauthorized overtime hours without formal management approval or sign-off","Employees using unauthorized cloud apps or devices, creating uncontrolled risk exposure outside security policies","Older legacy systems that have not received vendor security patches due to end-of-life support status"],answer:2,explanation:"Shadow IT bypasses corporate security controls, potentially exposing sensitive data and creating compliance violations.",optionExplanations:["Unapproved security software is a narrow IT governance issue around one tool category; shadow IT is the broader phenomenon covering any unauthorized technology adoption.","Unauthorized overtime is a human resources and labor policy matter, entirely unrelated to unsanctioned technology use, which is what shadow IT describes.","Shadow IT introduces uncontrolled risk because unauthorized apps lack corporate security review, monitoring, and data governance.","Unpatched legacy systems are a vulnerability management concern tied to end-of-life software; shadow IT specifically concerns unsanctioned technology adoption outside IT's visibility."]},
  {id:308,domain:A,question:"What is the purpose of network flow monitoring (NetFlow)?",options:["Analyze metadata about network conversations (source/destination, port, bytes, duration) to detect anomalies","Actively identify and block malicious network traffic in real time before it reaches its destination","Capture and permanently store the complete byte-for-byte payload content of every network packet transmitted","Apply strong encryption to network traffic exchanged between two communicating devices on the network"],answer:0,explanation:"NetFlow/IPFIX captures flow records (metadata only) enabling traffic pattern analysis and anomaly detection at scale.",optionExplanations:["NetFlow records capture traffic metadata — 5-tuple, byte counts, timestamps — enabling anomaly detection without storing full packets.","Actively blocking malicious traffic is the job of firewalls and intrusion prevention systems; NetFlow is a passive monitoring and analysis tool, not a blocking control.","Full packet capture and storage is performed by tools like Wireshark or a network sniffer; NetFlow instead records lightweight flow metadata only, not payload content.","Traffic encryption is provided by protocols such as TLS or IPsec; NetFlow instead analyzes the resulting traffic patterns without encrypting anything itself."]},
  {id:309,domain:O,question:"What is the purpose of endpoint hardening?",options:["Install a wider variety of productivity and convenience applications across all managed endpoint devices","Grant additional standard users elevated membership within the local administrator group on endpoints","Upgrade endpoint hardware components to maximize processing speed and overall system performance","Remove unnecessary services, disable unused ports, and configure security settings to minimize the attack surface"],answer:3,explanation:"Endpoint hardening reduces attack surface by removing default accounts, disabling unneeded services, and applying security baselines.",optionExplanations:["Installing more applications actually expands the attack surface by adding potential vulnerabilities; hardening instead works to remove and minimize unnecessary software.","Adding more users to administrator groups violates the principle of least privilege; hardening instead enforces minimum necessary access for all accounts.","Hardening may slightly reduce raw performance due to added security overhead; boosting speed is not its goal, security takes priority.","Endpoint hardening applies CIS benchmark configurations — disabling unused services, restricting privileges, enabling logging."]},
  {id:310,domain:O,question:"What is a known-good baseline in security?",options:["A visual diagram illustrating how network devices, routers, and switches are physically interconnected","The absolute maximum lockdown security configuration achievable on a given system regardless of usability impact","A continuously updated database listing signatures used by antivirus engines to identify known malware families","A documented snapshot of a system's normal, secure state used for comparison to detect changes"],answer:3,explanation:"A known-good baseline enables integrity monitoring — any deviation indicates unauthorized change or compromise.",optionExplanations:["A network topology diagram documents physical and logical connections between devices; a system baseline instead documents an individual system's configuration state.","The maximum possible lockdown configuration is a hardening target organizations aim toward; a baseline is instead the documented normal state used for comparison, not necessarily the strictest setting.","Malware signature lists are detection databases used by antivirus tools; a baseline instead documents a system's own expected normal configuration state.","A known-good baseline captures expected system configuration, files, and behavior to detect unauthorized modifications."]},
  {id:311,domain:P,question:"Which regulation requires organizations to report data breaches to affected individuals within 72 hours?",options:["PCI DSS","SOX","GDPR","HIPAA"],answer:2,explanation:"GDPR Article 33 requires notifying the supervisory authority within 72 hours of becoming aware of a data breach.",optionExplanations:["PCI DSS requires incident reporting to card brands but does not specify a 72-hour timeline to individuals.","SOX focuses on financial reporting accuracy for publicly traded companies, not data breach notification timelines.","GDPR requires supervisory authority notification within 72 hours and individual notification without undue delay.","HIPAA breach notification requires notification to individuals within 60 days; supervisory authority within 72 hours is GDPR."]},
  {id:312,domain:P,question:"What is the purpose of a data processing agreement (DPA)?",options:["A technical engineering specification detailing which encryption algorithms and key lengths must be implemented","A commercial software license agreement granting rights to use a specific data analytics platform","An internal, non-binding organizational policy describing how long different categories of data should be kept","A legally binding contract governing how a data processor handles personal data on behalf of a controller"],answer:3,explanation:"DPAs (required under GDPR) define the processor's obligations for processing personal data on behalf of the controller.",optionExplanations:["A technical encryption specification is an implementation standard for protecting data; a DPA instead defines the legal obligations and responsibilities between controller and processor.","Software licensing for analytics tools is governed by EULAs and vendor contracts unrelated to personal data handling; a DPA governs data processing relationships specifically.","An internal retention policy is a unilateral administrative document; a DPA is instead a binding bilateral contract with an external third-party processor, required under GDPR.","A DPA establishes legal obligations between data controllers and processors, required by GDPR for all processing relationships."]},
  {id:313,domain:P,question:"What is the concept of 'data minimization' in privacy?",options:["Compressing and using smaller data file formats purely to reduce overall storage infrastructure costs","Automatically purging all personal data records immediately once initial processing has been completed","Collecting only the minimum personal data necessary for the specified purpose","Applying strong encryption algorithms uniformly to all personal data an organization holds"],answer:2,explanation:"Data minimization (a GDPR principle) means collecting only what is strictly necessary, reducing privacy risk.",optionExplanations:["File size reduction through compression is a storage optimization technique; data minimization instead limits how much data is collected in the first place, regardless of file size.","Deleting data after processing relates to retention limits and disposal schedules; minimization is about restricting what gets collected from the very start, not deletion timing.","Data minimization collects only data that is adequate, relevant, and limited to what is necessary for the stated purpose.","Encryption protects data that has already been collected; minimization instead reduces the total volume of data at risk by limiting collection scope."]},
  {id:314,domain:O,question:"What is a security operations maturity model?",options:["A framework assessing the sophistication and effectiveness of a security operations program across capability levels","A technical benchmark comparing raw processing speed and detection accuracy across competing security tool vendors","A roster document listing which industry certifications each individual security team member currently holds","A simple inventory count tallying the total number of distinct security tools currently deployed in production"],answer:0,explanation:"SOC maturity models (like the SOC-CMM) assess capabilities from ad hoc (Level 1) to optimized, metrics-driven programs (Level 5).",optionExplanations:["Security maturity models assess people, process, and technology capabilities across progressive maturity levels.","Tool performance benchmarks measure individual product technical capability; maturity models instead assess the overall program's effectiveness across people, process, and technology.","Individual staff certifications are one input into overall capability, but a maturity model assesses organizational people, process, and technology together, not just credentials.","Tool count is a vanity metric that says little about effectiveness; maturity instead measures capability, process discipline, and outcome sophistication."]},
  {id:315,domain:T,question:"What is a living-off-the-land (LotL) attack?",options:["A targeted cyberattack aimed at compromising industrial control systems used in agricultural and farming equipment","Compromising a trusted third-party software vendor to distribute malware through legitimate update channels","Using legitimate system tools (PowerShell, WMI, Certutil) already present on the target to carry out malicious activity","Concealing malicious code inside seemingly innocuous environmental sensor data or telemetry readings"],answer:2,explanation:"LotL attacks use built-in OS tools to blend in with normal activity, evading detection by not dropping external malware.",optionExplanations:["Agricultural control systems are a category of OT/ICS targets attacked through separate industrial techniques; living-off-the-land is instead a general endpoint attack methodology.","A supply chain attack compromises a trusted vendor to distribute malware broadly; living-off-the-land instead uses tools already present on a system that's already been compromised.","LotL attacks use trusted, pre-installed tools (certutil, mshta, regsvr32) for malicious purposes, evading file-based detection.","Hiding data within environmental telemetry is not a recognized cyberattack category; living-off-the-land specifically refers to abusing legitimate, pre-installed system tools maliciously."]},
  {id:316,domain:T,question:"What is a pass-the-ticket attack?",options:["Systematically guessing large numbers of password combinations against the Kerberos authentication service","Capturing and resubmitting a victim's web browser session cookie to hijack their authenticated website session","Using a stolen Kerberos ticket to authenticate as the ticket's owner without knowing their password","Harvesting the plaintext or hashed passwords belonging to Kerberos service accounts from configuration files"],answer:2,explanation:"Pass-the-ticket extracts Kerberos tickets from memory (using Mimikatz) and reuses them to authenticate to services.",optionExplanations:["Brute force attacks systematically guess unknown passwords; pass-the-ticket instead reuses a valid ticket that has already been legitimately issued, no guessing required.","Replaying a stolen web session cookie is browser session hijacking, a separate technique; pass-the-ticket instead reuses a Kerberos authentication artifact directly.","Pass-the-ticket uses extracted Kerberos TGT or service tickets to authenticate without needing the account password.","Stealing service account passwords is a form of credential harvesting; pass-the-ticket instead uses an already-issued ticket directly, bypassing the need for any password."]},
  {id:317,domain:A,question:"What is a network tap?",options:["A specific firewall configuration rule set up to duplicate and forward matching traffic to a logging server","A desktop software application used to open, filter, and analyze previously captured PCAP packet files","A temporary wireless access point deployed specifically to test signal strength and coverage during a survey","A hardware device passively copying all traffic on a network link for monitoring without introducing latency"],answer:3,explanation:"A network tap passively copies traffic off a link (optical or electrical) to a monitoring device without affecting the original traffic.",optionExplanations:["A firewall rule that mirrors traffic describes a software port-mirroring configuration; a network tap is instead a dedicated hardware device installed inline on the cable.","PCAP analysis software such as Wireshark examines traffic that's already been captured; a tap is the physical hardware that performs the actual capturing.","A wireless access point provides network connectivity to client devices; a tap is physical hardware built specifically for passively duplicating wired network traffic.","A network tap is a passive hardware device that copies all traffic on a link to monitoring tools without adding latency or risk of packet loss."]},
  {id:318,domain:A,question:"What is SPAN (Switched Port Analyzer)?",options:["A standardized network security protocol used to authenticate devices before granting them access to a switch","A specialized handheld tool used to survey and monitor wireless signal strength across a coverage area","A dedicated firewall operating mode that deeply inspects application-layer traffic passing through the appliance","A switch feature that copies traffic from one or more ports to a designated monitoring port"],answer:3,explanation:"SPAN (port mirroring) configures a switch to copy frames from selected ports to a monitoring port for analysis by IDS/sniffers.",optionExplanations:["SPAN is a built-in switch capability for mirroring traffic, not a network authentication or security protocol at all.","Wireless signal monitoring uses separate specialized RF survey tools; SPAN is instead a wired switch feature for mirroring Ethernet traffic.","A firewall's deep packet inspection mode analyzes traffic actively passing through the device itself; SPAN instead provides a passive copy of traffic for external analysis tools.","SPAN configures a switch to mirror traffic from source ports to a destination monitoring port for network analysis."]},
  {id:319,domain:O,question:"What is the purpose of a post-incident review (lessons learned)?",options:["Compile and preserve formal legal evidence documentation to support potential litigation or law enforcement","Formally identify and hold accountable the specific individual or team responsible for causing the incident","Mark the incident record as resolved and closed within the organization's ticketing system","Analyze what happened, identify what worked and what didn't, and improve processes for the future"],answer:3,explanation:"Post-incident reviews identify root causes, process improvements, and control gaps to strengthen defenses against future incidents.",optionExplanations:["Preserving legal evidence is part of the chain-of-custody process during response; the lessons-learned review instead focuses on improving future performance, not evidentiary documentation.","Assigning blame is generally counterproductive and discourages honest reporting; lessons-learned reviews instead focus on systemic process improvements, not individual fault.","Closing the ticket is a simple administrative bookkeeping step; a lessons-learned review drives meaningful, substantive improvements to future incident response.","Post-incident reviews analyze the timeline, root cause, response effectiveness, and control gaps to improve future response."]},
  {id:320,domain:O,question:"What is the role of the incident response team (IRT)?",options:["Deliver regular security awareness training sessions and phishing simulations to all employees","Coordinate the technical and managerial response to security incidents from detection through recovery","Conduct a scheduled penetration test of external-facing systems once every calendar year","Oversee routine day-to-day information technology operations including helpdesk tickets and system maintenance"],answer:1,explanation:"The IRT (or CSIRT/CERT) detects, analyzes, contains, eradicates, and recovers from security incidents.",optionExplanations:["Security awareness training is delivered by HR and the broader security program on an ongoing basis; the IRT's focus is specifically incident handling.","The incident response team coordinates all aspects of incident handling from initial detection through final recovery and lessons learned.","Annual penetration tests are typically conducted by red teams or contracted third-party testers on a scheduled basis; the IRT instead handles live, unplanned incidents.","Routine day-to-day IT operations are managed by the general IT operations team; the IRT specifically activates to handle security incidents."]},
  {id:321,domain:G,question:"What is the purpose of a pre-shared key (PSK) in Wi-Fi security?",options:["Authenticate each connecting device using an individually issued digital certificate and private key pair","Automatically generate a distinct, dynamically-rotated cryptographic key for each individual connecting user session","A shared password used by all devices to authenticate and derive encryption keys for the wireless network","Apply encryption exclusively to 802.11 management frames while leaving regular data frames unprotected"],answer:2,explanation:"PSK (used in WPA2/WPA3 Personal) is a shared passphrase all devices use; enterprise networks use 802.1X instead.",optionExplanations:["Certificate-based authentication is used in WPA2/WPA3 Enterprise mode via 802.1X, an entirely separate mechanism from the shared passphrase used in PSK mode.","Dynamic per-user unique keys are a hallmark of enterprise 802.1X authentication, not PSK mode, where every device shares the identical passphrase.","A PSK is a shared passphrase configured on the AP and all client devices, deriving the encryption key from it.","Management frame protection is a separate feature (802.11w); PSK's role is deriving the key used to encrypt regular data frame traffic."]},
  {id:322,domain:G,question:"What is the purpose of a Kerberos KDC?",options:["Process and respond to LDAP directory search and lookup queries for stored user account attributes","Translate internal private IP addresses into a single shared external public-facing internet address","Issue and digitally sign X.509 TLS certificates that clients present for secure encrypted web browsing sessions","Issue Ticket Granting Tickets and service tickets enabling authenticated access without transmitting passwords"],answer:3,explanation:"The Key Distribution Center (KDC) contains the Authentication Server (AS) and Ticket Granting Server (TGS) for Kerberos.",optionExplanations:["LDAP directory query handling is performed by directory services like Active Directory; the KDC uses that directory for account lookups but performs its own distinct ticket-issuing function.","NAT translates IP addresses for routing purposes; the KDC instead manages cryptographic authentication tickets and has nothing to do with address translation.","TLS certificates for encrypted web sessions are issued by Certificate Authorities through a completely separate PKI process; the KDC instead issues Kerberos authentication tickets.","The Key Distribution Center (KDC) contains the Authentication Server (AS) and Ticket Granting Server (TGS) for Kerberos."]},
  {id:323,domain:T,question:"What is the purpose of network reconnaissance tools like Nmap?",options:["Apply strong end-to-end encryption to all network traffic transmitted between two communicating hosts","Actively detect and automatically block malicious network traffic before it reaches its intended target","Establish an encrypted VPN tunnel connection between a remote client and the corporate network","Discover hosts, open ports, and services on a network for security assessment or attack planning"],answer:3,explanation:"Nmap is a network scanner used to discover live hosts, open ports, running services, and OS fingerprints.",optionExplanations:["Nmap does not encrypt any traffic; it instead actively probes remote systems to discover what services and ports are running.","Blocking malicious traffic is performed by firewalls and intrusion prevention systems; Nmap is purely a reconnaissance and discovery tool, not a blocking control.","VPN tools establish encrypted tunnels for secure remote connectivity; Nmap is instead a network discovery and port scanning utility with no encryption function.","Nmap discovers network topology, open ports, service versions, and OS details — essential for both defense and offense."]},
  {id:324,domain:T,question:"What is a credential harvesting attack?",options:["Running offline computational attacks against stolen password hash databases to recover plaintext passwords","Systematically submitting thousands of automated password guesses against a website's public login page","Programmatically generating lists of common factory-default username and password combinations for IoT devices","Tricking users into entering their credentials on a fake site or through other means to steal them"],answer:3,explanation:"Credential harvesting tricks users into submitting credentials to attacker-controlled pages through phishing, fake sites, or malware.",optionExplanations:["Hash cracking is an offline computational attack against a stolen password database; harvesting instead captures live plaintext credentials directly from a deceived user.","Brute forcing systematically guesses credentials through repeated automated attempts; harvesting instead tricks users into voluntarily typing their real credentials into a fake interface.","Generating default credential lists is a configuration-based attack targeting weak factory settings; harvesting instead captures real, unique user credentials through deception.","Credential harvesting steals credentials through deception (phishing pages, fake login forms) rather than technical cracking."]},
  {id:325,domain:A,question:"What is the purpose of rate limiting in web security?",options:["Apply end-to-end encryption to protect the confidentiality of data returned in every API response","Optimize backend caching and database queries so that every web server response returns noticeably faster","Record a detailed, timestamped log entry for every single incoming request the server receives","Restrict the number of requests from a single source in a time window to prevent abuse, DoS, or brute force"],answer:3,explanation:"Rate limiting prevents brute force, credential stuffing, and API abuse by limiting how many requests a client can make per unit time.",optionExplanations:["Response encryption is handled by TLS to protect confidentiality in transit; rate limiting instead controls how frequently a client is allowed to make requests.","Rate limiting actually slows or blocks excessive requests from any single source rather than speeding up responses; performance optimization is a separate concern entirely.","Request logging is performed by the web server and forwarded to a SIEM for analysis; rate limiting is instead an active control that restricts request frequency.","Rate limiting caps request frequency to prevent password brute force, scraping, and API-based DoS attacks."]},
  {id:326,domain:P,question:"Which of the following is a primary security control objective of HIPAA Security Rule?",options:["Explicitly mandate multi-factor authentication be enforced for every single user accessing any system","Ensure the confidentiality, integrity, and availability of all ePHI","Mandate that every single email message sent within a covered entity be individually encrypted","Explicitly forbid covered entities from ever storing patient health information in any cloud environment"],answer:1,explanation:"The HIPAA Security Rule requires covered entities to protect the CIA of all electronic protected health information.",optionExplanations:["HIPAA does not explicitly mandate MFA by name, though it is a widely recommended safeguard supporting the access control requirements.","The HIPAA Security Rule's overall objective is to ensure CIA of all ePHI through administrative, physical, and technical safeguards.","HIPAA recommends but does not specifically mandate blanket email encryption as a required control for every message.","HIPAA does not prohibit cloud storage of health data; it instead requires any such cloud arrangement be covered by a signed Business Associate Agreement (BAA)."]},
  {id:327,domain:O,question:"What is the function of a security information broker?",options:["Purchase and resell stolen personal and financial data on underground criminal marketplaces","Supply exclusively curated threat intelligence feeds without handling any other type of security data","Coordinate and track third-party vendor security questionnaires and risk assessment reviews","Aggregate and normalize security data from multiple sources for analysis and correlation"],answer:3,explanation:"A security data broker aggregates logs and events from multiple disparate systems into a common format for analysis.",optionExplanations:["Buying and selling stolen data describes a criminal data broker; a security information broker is instead a legitimate tool aggregating an organization's own security data.","Threat intelligence is just one input type; a security information broker handles and normalizes all categories of security data, not threat feeds exclusively.","Vendor security assessments are a third-party risk management activity conducted by procurement or GRC teams, not a data broker function.","A security information broker normalizes and aggregates security data from diverse sources to enable unified analysis."]},
  {id:328,domain:O,question:"What is the purpose of a continuous monitoring program?",options:["Deliver a mandatory formal security policy training refresher course to all staff annually","Perform a single comprehensive formal security assessment conducted just once per calendar year","Roll out accumulated security patches to production systems once every fiscal quarter","Maintain ongoing awareness of information security, vulnerabilities, and threats in real time"],answer:3,explanation:"Continuous monitoring provides real-time or near-real-time visibility into security posture, replacing periodic point-in-time assessments.",optionExplanations:["Annual staff training is one component of the broader security program; continuous monitoring is instead an operational technical capability tracking systems in real time.","Annual assessments are periodic point-in-time snapshots; continuous monitoring instead provides persistent, ongoing visibility rather than a once-a-year check.","Quarterly patch deployment describes a fixed patch management cadence; continuous monitoring instead detects vulnerabilities as they emerge, independent of the patching schedule.","Continuous monitoring maintains persistent awareness of control effectiveness, new vulnerabilities, and threat indicators."]},
  {id:329,domain:G,question:"What is the PBKDF2 algorithm used for?",options:["Encrypting large volumes of bulk file and disk data using a fast symmetric cipher","Deriving cryptographic keys from passwords using salt and iteration count","Negotiating and exchanging a fresh session key between client and server during a TLS handshake","Mathematically generating a matched public and private asymmetric key pair for use in signing"],answer:1,explanation:"PBKDF2 (Password-Based Key Derivation Function 2) strengthens passwords by applying HMAC many times with a salt.",optionExplanations:["Bulk data encryption uses fast symmetric ciphers such as AES; PBKDF2 instead derives the key that such encryption would use, not perform the encryption itself.","PBKDF2 takes a password, salt, iteration count, and desired key length, producing a strong cryptographic key.","TLS session key exchange relies on protocols like Diffie-Hellman; PBKDF2 is instead specifically for deriving keys from passwords, unrelated to live session negotiation.","Asymmetric key pairs are generated by algorithms such as RSA or ECDSA; PBKDF2 instead derives a symmetric key from a password, not a key pair."]},
  {id:330,domain:T,question:"What is the purpose of obfuscation in malware?",options:["Increase the execution speed and runtime efficiency of the malicious payload once it activates","Make malware code harder to analyze and detect by security tools","Enable the malware to replicate and propagate itself faster across additional connected systems","Encrypt a victim's files and hold the decryption key for ransom payment"],answer:1,explanation:"Malware obfuscation (encoding, packing, polymorphism) disguises code to evade signature-based detection and complicate reverse engineering.",optionExplanations:["Obfuscation typically adds processing overhead and can slightly reduce execution efficiency; its actual goal is evading detection, not improving performance.","Malware obfuscation techniques (base64 encoding, packing, string encryption) make analysis and signature detection harder.","Faster propagation is achieved through network or removable-media spreading techniques; obfuscation is instead about evading analysis and detection, not spreading speed.","Encrypting victim files for ransom is what ransomware payloads do to data; obfuscation instead hides the malware's own code from analysis, not victim data."]},
  {id:331,domain:A,question:"What is network address translation (NAT) and how does it help security?",options:["It categorically blocks every single inbound connection attempt from reaching any internal host by default","It applies strong end-to-end encryption to all traffic exchanged between internal hosts and external systems","It verifies user identity credentials before granting devices authenticated access to the network","It maps private internal IPs to a public IP, hiding internal network topology from external observers"],answer:3,explanation:"NAT hides internal IP addressing from external attackers, reducing reconnaissance information about the internal network.",optionExplanations:["NAT can incidentally make unsolicited inbound connections harder due to the lack of a mapping table entry, but blocking connections is really firewall behavior, not NAT's core function.","NAT translates addresses but performs no encryption of the traffic itself; VPNs and TLS are the mechanisms that actually provide encryption.","Authentication is handled by IAM systems and protocols like 802.1X; NAT is purely an address translation mechanism with no authentication role.","NAT hides the internal network structure by presenting a single public IP, making it harder for attackers to map internal topology."]},
  {id:332,domain:A,question:"What is the purpose of 802.11w (Protected Management Frames)?",options:["Apply encryption algorithms to protect the payload contents of regular wireless data frames","Serve as a completely separate, standalone backward-compatibility layer required only for legacy WPA3 devices","Increase maximum achievable wireless throughput speeds by optimizing the radio modulation scheme","Protect 802.11 management frames (deauth, disassoc) from spoofing and injection attacks"],answer:3,explanation:"802.11w protects management frames so attackers cannot send fake deauthentication frames to disconnect clients.",optionExplanations:["Data frame payload encryption is provided by WPA2/WPA3's CCMP or GCMP ciphers; 802.11w instead specifically protects management frames, not data frame content.","802.11w is a security amendment in its own right, and WPA3 actually mandates its use rather than 802.11w merely providing legacy compatibility for WPA3.","Protecting management frames adds cryptographic overhead rather than improving throughput; 802.11w's purpose is security, not speed.","802.11w (PMF) authenticates management frames preventing deauthentication attacks used to force client disconnections."]},
  {id:333,domain:T,question:"What is a JPEG or PDF file used to deliver malware called?",options:["A rootkit","A macro virus","A bootkit","A malicious document or lure"],answer:3,explanation:"Malicious documents (maldocs) embed exploits or malicious macros in PDFs, Office files, or image metadata to deliver malware.",optionExplanations:["A rootkit is persistent malware hiding at the OS level; a malicious document is a delivery mechanism.","Macro viruses are a subset of maldocs; malicious documents include PDF exploits and image file exploits as well.","A bootkit infects the MBR or boot process; malicious documents exploit document viewers and macro engines.","Maldocs are weaponized files (PDF exploits, Office macros) used to deliver malware when opened by victims."]},
  {id:334,domain:O,question:"What is the purpose of network segmentation in limiting ransomware spread?",options:["Completely block ransomware payloads from ever successfully encrypting files on the initially infected host","Limit how far ransomware can spread by restricting its ability to reach other network segments","Identify and flag ransomware code as malicious before it ever begins executing on a host","Accelerate the restoration of encrypted files by streamlining the backup recovery process itself"],answer:1,explanation:"Segmentation limits ransomware's lateral movement, confining it to the segment where it first landed.",optionExplanations:["Segmentation alone cannot stop file encryption on the already-infected host itself; it instead limits how far the infection can spread afterward.","Segmentation restricts ransomware from spreading across the entire network by limiting access between segments.","Pre-execution detection is performed by EDR tools and email security gateways; segmentation instead limits spread after detection has already failed.","Recovery speed depends on backup quality and disaster recovery planning; segmentation instead limits the scope of damage rather than accelerating restoration."]},
  {id:335,domain:P,question:"What is the concept of 'right to erasure' (right to be forgotten) under GDPR?",options:["Organizations are legally required to instantly and unconditionally delete every record the moment any request ever arrives","Individuals can request deletion of their personal data under certain conditions; organizations must comply or cite legal grounds to refuse","This right is legally restricted so it only applies to personal data that has already been retained for over a decade","This right under GDPR applies exclusively to sensitive banking and financial account records, excluding all other data types"],answer:1,explanation:"GDPR Article 17 grants individuals the right to request data deletion when data is no longer necessary or consent is withdrawn.",optionExplanations:["Organizations do not have to delete all data immediately upon request; erasure rights include several conditions and exceptions such as legal obligations or public interest.","GDPR's right to erasure allows data subjects to request deletion under specific conditions; organizations may refuse with legal justification.","GDPR's erasure and retention principles are not tied to any specific minimum age of the data; the right can apply regardless of how long data has been held.","GDPR's right to erasure covers all categories of personal data broadly, not exclusively financial records."]},
  {id:336,domain:G,question:"What is the purpose of certificate transparency (CT) logs?",options:["Securely store backup copies of CA private keys to enable emergency key recovery","Formally revoke certificates identified as compromised and publish that status to a certificate revocation list","A public audit log of all TLS certificates issued, allowing detection of misissued certificates","Fully replace OCSP as the sole mechanism clients use to check real-time certificate revocation status"],answer:2,explanation:"CT logs create an auditable, append-only record of all certificates issued by CAs, enabling domain owners to detect unauthorized certs.",optionExplanations:["Private keys must never be placed into any public log; CT logs contain only public certificate data, never private key material.","Certificate revocation is handled through CRLs and OCSP responders; CT logs instead serve an auditing and detection function for tracking issuance, not revocation.","CT logs provide public visibility into all certificates issued, so domain owners can spot unexpected or fraudulent certificates.","OCSP continues to handle real-time revocation checking; CT logs serve the separate purpose of auditing certificate issuance for detection of fraud."]},
  {id:337,domain:G,question:"What is a certificate signing request (CSR)?",options:["A formal request submitted to a CA asking that a specific already-issued certificate be revoked immediately","A message sent to a CA containing the public key and identity information, requesting a signed certificate","A separate formal process submitted to extend the validity period of a certificate nearing expiration","The cryptographic digital signature a CA applies to a certificate, vouching for its authenticity"],answer:1,explanation:"A CSR contains the entity's public key and identity (CN, SAN, organization) and is signed with the corresponding private key.",optionExplanations:["Certificate revocation requests are separate submissions handled through the CA's revocation process; a CSR is instead for obtaining a brand-new certificate, not revoking one.","A CSR is submitted to the CA with the applicant's public key and information; the CA signs and returns a certificate.","Renewal generally involves submitting a fresh CSR as part of the process, but the renewal request itself is a distinct step, not synonymous with the CSR.","The digital signature on a certificate is the CA's own cryptographic attestation; a CSR is instead the applicant's request that precedes and requests that signature."]},
  {id:338,domain:T,question:"What is a pass-the-certificate attack?",options:["Fabricating an entirely new root CA certificate from scratch to impersonate a trusted certificate authority","Directly logging into a victim's account using a plaintext password stolen through a keylogger","Using a stolen digital certificate and key pair to authenticate without knowing the password","Sending phishing emails that exploit fake browser certificate warning messages to trick users into clicking"],answer:2,explanation:"Pass-the-certificate reuses stolen certificates and private keys (from certificate stores) to authenticate to services that accept certificate authentication.",optionExplanations:["Forging an entirely new root CA certificate would require compromising the CA's own private key; pass-the-certificate instead reuses legitimate certificates already stolen from a victim.","Using a stolen password is straightforward credential theft; pass-the-certificate instead uses cryptographic certificate and key material rather than a password at all.","Pass-the-certificate extracts certificate/key pairs from certificate stores and uses them to authenticate as the victim.","Phishing that exploits fake certificate warnings tricks users into ignoring legitimate browser errors; it is unrelated to pass-the-certificate, which uses genuine stolen credentials."]},
  {id:339,domain:O,question:"What is the purpose of a deception technology solution?",options:["Fully replace all traditional firewall, IDS, and SIEM detection controls across the entire environment","Proactively block and stop every intrusion attempt before an attacker ever reaches the network perimeter","Instruct security staff on offensive attacker methodologies and tools through structured red team training","Create fake assets and data throughout the environment to detect and slow down attackers who enter the network"],answer:3,explanation:"Deception technology (honeypots, honeyfiles, fake credentials) alerts defenders when attackers interact with decoy assets.",optionExplanations:["Deception supplements rather than replaces existing detection layers such as firewalls, IDS/IPS, and SIEM.","Deception technology detects attackers already inside the network; it cannot prevent an attack from entering the environment in the first place.","Red team training teaches defenders attacker techniques directly; deception technology is instead a passive defensive detection mechanism, not a training program.","Deception technologies create attractive fake targets that alert defenders the moment an attacker interacts with them."]},
  {id:340,domain:P,question:"What is the purpose of a security awareness training program metric?",options:["Assess the hands-on technical proficiency and certification level of dedicated security team members","Tally the total inventory count of distinct security software tools currently deployed across the organization","Simply record whether employees showed up to a mandatory training session for compliance checklists","Measure the effectiveness of training in reducing security risk behaviors among employees"],answer:3,explanation:"Meaningful metrics (phishing click rates, reporting rates, policy quiz scores) measure behavioral change, not just compliance.",optionExplanations:["Technical staff skills are assessed through separate certification exams and competency evaluations, not through security awareness training metrics aimed at general employees.","Tool count is a technical inventory metric unrelated to human behavior; training metrics instead measure whether behavior actually changed.","Attendance tracking satisfies a compliance checkbox but says nothing about whether the training actually changed employee behavior.","Training metrics quantify whether employees recognize and avoid threats — e.g., reduction in phishing click-through rates."]},
  {id:341,domain:G,question:"What is the purpose of a security assertion markup language (SAML) assertion?",options:["Track and publish the current revocation status of issued digital certificates","Produce cryptographic digital signatures attached to outgoing email messages for sender verification","Apply a one-way hashing algorithm to protect a user's stored password before it is saved","An XML document passed from an identity provider to a service provider confirming user authentication"],answer:3,explanation:"A SAML assertion is an XML statement from the IdP to the SP declaring the user's identity and attributes after authentication.",optionExplanations:["Certificate revocation status is tracked via CRLs and OCSP; SAML is instead a federation and single sign-on protocol, unrelated to certificate lifecycle management.","Email digital signatures rely on standards like S/MIME or PGP; a SAML assertion is instead a web SSO authentication message, unrelated to email.","Password protection through hashing is handled by the identity store itself; a SAML assertion is instead a message confirming that authentication already occurred, unrelated to password storage.","SAML assertions carry the IdP's signed confirmation that a user has authenticated, enabling SSO across services."]},
  {id:342,domain:G,question:"What is OpenID Connect (OIDC)?",options:["A dedicated transport encryption protocol designed specifically to secure data exchanged between API endpoints","An identity layer built on top of OAuth 2.0 providing authentication and identity information","A formal technical standard defining the structure and fields of X.509 digital certificates","A protocol dedicated to generating, distributing, and rotating cryptographic keys across an organization"],answer:1,explanation:"OIDC adds an identity layer to OAuth 2.0, providing ID tokens (JWT) with user identity claims for authentication.",optionExplanations:["API transport encryption is provided by TLS; OpenID Connect is instead an authentication and identity protocol layered on OAuth 2.0, unrelated to transport encryption.","OpenID Connect extends OAuth 2.0 with authentication capabilities, issuing ID tokens containing user identity information.","Digital certificates follow the separate X.509 standard; OIDC instead uses signed JWT tokens to convey identity, unrelated to certificate formatting.","Key management is handled by dedicated KMS solutions; OIDC instead manages identity tokens for authentication, not cryptographic key lifecycle."]},
  {id:343,domain:T,question:"What is a fileless attack that uses PowerShell for malicious purposes called?",options:["A macro virus embedded within a malicious Office document","A PowerShell-based living-off-the-land attack","A kernel-level rootkit that hides its presence","A destructive wiper attack that erases data"],answer:1,explanation:"Attackers use legitimate PowerShell to download payloads, manipulate systems, and evade detection without dropping files.",optionExplanations:["Macro viruses are malicious code embedded in Office documents like Word or Excel; PowerShell-based attacks instead run directly in memory without a document macro.","Using PowerShell for malicious purposes is a prime example of living-off-the-land — no external malware files needed.","Rootkits hide at the kernel level to conceal their presence; PowerShell-based attacks instead operate at the user or OS scripting level, not the kernel.","Wiper attacks are designed purely to destroy data; PowerShell-based attacks may destroy, steal, or persist depending on the attacker's specific objectives."]},
  {id:344,domain:T,question:"What is the primary security risk of IoT devices?",options:["IoT devices require complex, time-consuming initial setup procedures that frustrate end users","IoT devices carry a high upfront purchase and licensing cost that strains procurement budgets","IoT devices generate excessive network bandwidth consumption that degrades overall network performance","IoT devices often lack security updates, use default credentials, and have minimal security features"],answer:3,explanation:"IoT devices frequently run outdated firmware, use default credentials, and cannot be patched, creating persistent network vulnerabilities.",optionExplanations:["Configuration difficulty is a usability and deployment challenge; the core security risk is the lack of built-in security controls and update mechanisms, not setup complexity.","Device cost is a procurement and budgeting consideration, not a security risk in itself.","Bandwidth consumption is a performance and capacity concern; the primary security risk instead stems from weak or absent security controls on the devices themselves.","IoT devices often run stripped-down OSes without update mechanisms, factory-default passwords, and no security tooling."]},
  {id:345,domain:A,question:"What is a VPC (Virtual Private Cloud)?",options:["A fully dedicated, physically separate private data center facility built and hosted at a cloud provider's site","An isolated, logically defined section of a public cloud provider's infrastructure dedicated to one customer","An encrypted virtual private network tunnel that remote users connect through to reach corporate resources","A specific type of managed VPN service hosted and operated entirely within a cloud provider's network"],answer:1,explanation:"A VPC provides network isolation within a public cloud, allowing customers to define their own IP ranges, subnets, and routing.",optionExplanations:["A private data center implies dedicated physical facilities and hardware; a VPC is instead shared cloud infrastructure that is only logically isolated for one customer.","A VPC is a logically isolated section of a cloud provider's network that a customer fully controls (subnets, routing, security groups).","A VPN creates an encrypted tunnel for remote connectivity; a VPC is instead a logically isolated network construct within a cloud provider, not a tunnel technology.","While a VPC can host VPN gateway endpoints, it is not itself a type of VPN service."]},
  {id:346,domain:A,question:"What is the purpose of a cloud security posture management (CSPM) tool?",options:["Apply encryption algorithms to protect data stored within cloud storage buckets and databases","Completely replace and eliminate the need for any cloud provider's native security controls","Continuously monitor cloud environments for misconfigurations and compliance violations","Establish encrypted VPN gateway connections granting remote users access to cloud-hosted resources"],answer:2,explanation:"CSPM tools automatically detect and remediate cloud misconfigurations (public S3 buckets, open security groups) that expose organizations.",optionExplanations:["Data encryption is a cloud security control in its own right; CSPM instead monitors the configuration of those controls, rather than performing encryption itself.","CSPM adds visibility and governance layered on top of native cloud controls; it does not replace or eliminate them.","CSPM identifies cloud infrastructure misconfigurations, policy violations, and compliance deviations automatically.","VPN access to cloud resources is provided by cloud VPN gateways; CSPM instead monitors security configurations, unrelated to establishing connectivity."]},
  {id:347,domain:O,question:"What is the OODA loop and how does it apply to security?",options:["A formal system for categorizing incidents into predefined severity tiers and priority levels","A standardized protocol governing how network devices report monitoring telemetry data","A decision cycle (Observe, Orient, Decide, Act) used by security teams to outpace attackers","A structured framework used specifically for reverse-engineering and analyzing captured malware samples"],answer:2,explanation:"The OODA loop enables faster decision-making cycles than attackers — observing what's happening, orienting to context, deciding, and acting.",optionExplanations:["Incident classification uses defined severity levels and categories to prioritize response; OODA is instead the decision-making model for how a team reacts and acts.","Network monitoring protocols collect telemetry data from devices; OODA is instead the cognitive framework for acting on that collected data, not a protocol itself.","The OODA (Observe, Orient, Decide, Act) loop helps security teams make rapid, informed decisions to stay ahead of attackers.","Malware analysis uses techniques like sandboxing and reverse engineering to examine samples; OODA is instead a general decision-making framework, unrelated to malware specifically."]},
  {id:348,domain:O,question:"What does IoC (Indicator of Compromise) differ from an IoA (Indicator of Attack)?",options:["IoCs are evidence of past compromise; IoAs are behavioral patterns indicating an ongoing attack","IoCs are used exclusively to prevent attacks outright, while IoAs are used solely for after-the-fact detection","IoAs consistently produce more accurate and reliable results than IoCs do in every detection scenario","IoCs and IoAs describe the exact identical concept and are used completely interchangeably by analysts"],answer:0,explanation:"IoCs (file hashes, IPs) are forensic artifacts after compromise; IoAs (lateral movement patterns) indicate an attack in progress.",optionExplanations:["IoCs are post-compromise artifacts (file hashes, registry keys); IoAs are real-time behavioral indicators of active attack progression.","The roles are reversed from this description: IoCs mainly support detection and forensics after the fact, while IoAs can enable earlier detection during an active, ongoing attack.","Both indicator types have distinct value; IoAs often provide earlier warning of behavior in progress, but neither is universally more accurate than the other in every case.","IoCs and IoAs serve genuinely different purposes across the attack timeline, so they are not interchangeable or identical concepts."]},
  {id:349,domain:P,question:"What is the concept of 'privacy engineering'?",options:["Delivering structured classroom training sessions to developers covering GDPR legal compliance requirements","Designing and constructing large-scale surveillance and monitoring systems for law enforcement agencies","Systematically integrating privacy requirements into technical systems throughout the engineering lifecycle","Conducting a formal, scheduled review of written privacy policies once every calendar year"],answer:2,explanation:"Privacy engineering applies technical methods to identify and mitigate privacy risks throughout system design and development.",optionExplanations:["GDPR compliance training raises developer awareness of legal requirements; privacy engineering is the deeper technical discipline of actually building privacy protections into systems.","Building surveillance systems runs counter to privacy protection goals and is essentially the opposite of what privacy engineering aims to achieve.","Privacy engineering integrates privacy impact analysis, data flow mapping, and privacy-preserving design into the development process.","Annual policy auditing is a periodic compliance-checking activity; privacy engineering is instead a proactive, ongoing technical design methodology integrated throughout development."]},
  {id:350,domain:G,question:"What is a hybrid encryption scheme?",options:["Combining two entirely different symmetric encryption algorithms together to encrypt the same dataset twice","Maintaining one dedicated key strictly for authentication purposes and a completely separate key for encryption","Encrypting the same set of data twice in succession, each pass using a different symmetric key","Using asymmetric encryption to protect a symmetric key, then symmetric encryption for bulk data"],answer:3,explanation:"Hybrid encryption (used in TLS, PGP) uses asymmetric to securely exchange a symmetric key, then symmetric for fast bulk data encryption.",optionExplanations:["Combining two symmetric algorithms is a form of double or cascade encryption, not what defines hybrid encryption, which pairs asymmetric with symmetric techniques.","Using separate keys for authentication versus encryption is a dual-key management practice; hybrid encryption is specifically about combining asymmetric and symmetric algorithms for efficiency.","Double encryption with different keys of the same algorithm type is a layering technique; hybrid encryption specifically combines asymmetric and symmetric algorithm types together.","Hybrid encryption combines the key management advantages of asymmetric with the speed advantages of symmetric encryption."]},
  {id:351,domain:T,question:"What is a watering hole attack?",options:["Compromising websites frequently visited by a target group to infect their systems","Sending individually crafted phishing emails directly to a small number of specific targeted individuals","Overwhelming a target server with massive volumes of traffic to force a service outage","Silently intercepting and relaying communications exchanged directly between two specific parties"],answer:0,explanation:"Watering hole attacks compromise websites that the target group frequently visits, allowing attackers to infect visitors without direct contact.",optionExplanations:["Watering hole attacks compromise websites that the target group frequently visits, allowing attackers to infect visitors through drive-by downloads or exploits.","Direct spear phishing targets individuals via email; a watering hole attack instead passively waits for targets to visit an already-compromised website.","Flooding a server with traffic describes a denial-of-service attack, unrelated to compromising a website that targets happen to visit.","Intercepting communications between two parties describes a man-in-the-middle attack; a watering hole attack instead relies on compromising websites the targets voluntarily visit."]},
  {id:352,domain:G,question:"What is key escrow in cryptography?",options:["Splitting a single encryption key into fragments and distributing them across multiple independent servers","Deriving a new shared symmetric key collaboratively from a mutually agreed secret value","A system where a copy of an encryption key is held by a trusted third party for authorized recovery","Physically storing an organization's active encryption keys inside a tamper-resistant hardware security module appliance"],answer:2,explanation:"Key escrow allows authorized parties (law enforcement, recovery agents) to access encrypted data by retrieving the stored key copy.",optionExplanations:["Distributing key fragments across servers describes key splitting or threshold cryptography; escrow instead places one complete copy with a single trusted third party.","Deriving keys from a shared secret describes Diffie-Hellman key agreement; escrow is instead about securely storing copies of already-generated keys for later recovery.","Key escrow allows authorized parties (law enforcement, recovery agents) to access encrypted data by retrieving the stored key copy.","HSM storage is a technical protection mechanism keeping the original key safe; key escrow specifically involves deliberately giving a separate copy to a trusted third party for recovery."]},
  {id:353,domain:A,question:"What is a jump server (jump box) used for in network security?",options:["Measuring and testing overall network throughput, latency, and performance using dedicated benchmarking software","Executing scheduled automated vulnerability scans against network devices to identify unpatched flaws","Forwarding and routing network packets between different VLANs at Layer 3 of the OSI model","A hardened intermediate host used to access systems in isolated or high-security network segments"],answer:3,explanation:"Jump servers provide a controlled access point to sensitive network zones, logging all activity and reducing direct exposure of internal systems.",optionExplanations:["Network performance testing uses dedicated benchmarking tools such as iPerf; a jump box instead controls and logs privileged administrative access, unrelated to performance testing.","Vulnerability scanning is performed by dedicated tools such as Nessus or Qualys; jump boxes are instead access control checkpoints, not scanning tools.","Routing traffic between VLANs is performed by Layer 3 switches or routers; a jump box instead controls administrative access paths into sensitive network segments.","A jump server (or bastion host) sits between the administrator and target systems, logging and controlling privileged access to sensitive zones."]},
  {id:354,domain:O,question:"What is the primary purpose of security information and event management (SIEM) correlation rules?",options:["Automatically deploying vendor-released patches to remediate discovered software vulnerabilities across the environment","Identifying patterns across multiple log sources that indicate potential security incidents","Reducing storage costs by compressing archived log files before moving them to long-term cold storage","Applying strong encryption algorithms to protect the confidentiality of stored log data at rest"],answer:1,explanation:"SIEM correlation rules analyze events from multiple sources to detect attack patterns like brute force, lateral movement, or data exfiltration.",optionExplanations:["Patch management addresses known vulnerabilities directly; SIEM correlation instead detects exploitation attempts and other security events, not remediation itself.","Correlation rules match events across sources — failed logins followed by success, then large data transfers — to surface attack sequences.","Log compression reduces storage costs for archived data; SIEM correlation instead extracts security meaning and patterns from log content, not storage efficiency.","Log encryption protects data confidentiality at rest; SIEM correlation instead analyzes log content to detect meaningful threat patterns, not to encrypt it."]},
  {id:355,domain:T,question:"What distinguishes a zero-day exploit from a known vulnerability exploit?",options:["Exploits targeting already-published vulnerabilities are inherently more reliable and effective than any zero-day exploit","A zero-day targets a vulnerability unknown to the vendor, while known exploits target published vulnerabilities","Zero-day vulnerabilities are exclusively found within core operating system code and never affect applications","Zero-day exploits pose significantly less risk to organizations than exploits targeting already publicly known vulnerabilities"],answer:1,explanation:"Zero-day exploits target vulnerabilities the vendor doesn't know about, so no patch exists, making them extremely valuable and dangerous.",optionExplanations:["Known exploits may benefit from publicly available proof-of-concept code, but zero-days hold the advantage of no defenses or patches yet being in place, not the reverse.","A zero-day exploit targets a previously unknown vulnerability, giving defenders zero days to patch before exploitation occurs.","Zero-day vulnerabilities can affect any software layer, including browsers, applications, and firmware, not exclusively operating systems.","Zero-days are typically more dangerous, not less, because no patch exists yet and detection signatures have not been developed."]},
  {id:356,domain:P,question:"What is the purpose of a data retention policy?",options:["To automatically replicate data across multiple geographic locations and storage systems for redundancy and disaster recovery purposes","To keep all organizational data permanently in storage regardless of its age, type, or ongoing business or legal necessity","To categorize data according to its sensitivity level and assign appropriate handling and access restrictions","To define how long different data types should be kept and when they must be securely deleted"],answer:3,explanation:"Data retention policies balance legal/regulatory requirements (keeping records) with privacy obligations (deleting personal data when no longer needed).",optionExplanations:["Data replication across locations is a business continuity and redundancy control; retention policies instead govern how long data is kept before deletion.","Keeping all data permanently regardless of necessity creates excessive storage costs and privacy liabilities; retention policies set defined timelines instead.","Data classification assigns sensitivity levels and handling rules; retention policies separately determine how long each classification of data should be kept.","Retention policies specify periods for different data types (7 years for financial, 3 years for HR) and mandate secure deletion after those periods."]},
  {id:357,domain:A,question:"What is network segmentation and why is it a security control?",options:["Filtering and scanning email attachments at the network gateway to block malicious file delivery","Increasing the available network bandwidth to improve data throughput and reduce congestion during peak usage periods","Encrypting all network traffic end-to-end so that intercepted packets cannot be read by unauthorized parties","Dividing a network into isolated zones to limit lateral movement and contain breaches"],answer:3,explanation:"Network segmentation contains breaches by limiting how far attackers can move — a compromised guest network can't reach production systems.",optionExplanations:["Email gateway filtering protects against malicious attachments and content; segmentation controls network-level communication paths rather than message content.","Increasing bandwidth is a performance optimization concern unrelated to security; segmentation is a security architecture control that limits attacker movement.","Traffic encryption (TLS/IPsec) protects data confidentiality in transit; segmentation instead controls which systems are permitted to communicate with each other.","Segmentation creates isolated zones (DMZ, production, HR, guest) with firewall rules between them, limiting blast radius if one zone is compromised."]},
  {id:358,domain:O,question:"What is the goal of a tabletop exercise in incident response?",options:["Measuring network latency and throughput degradation while the environment is under simulated live attack conditions","Testing the technical response tools and automated systems used during an actual live incident response","Validating that backup restoration procedures actually recover data correctly within the required recovery time","A discussion-based simulation where team members work through a scenario to identify gaps in plans and procedures"],answer:3,explanation:"Tabletop exercises identify communication gaps, unclear responsibilities, and missing procedures without executing actual response actions.",optionExplanations:["Measuring network performance under attack is a technical stress test; tabletop exercises focus on process and decision-making gaps, not network performance metrics.","Testing technical tools occurs in functional exercises and live drills; a tabletop exercise is purely discussion-based and does not involve operating actual systems.","Backup restoration validation is a technical recovery test performed separately; tabletop exercises focus on people and process rather than technical system recovery.","Tabletop exercises walk through a hypothetical scenario verbally, revealing gaps in roles, escalation paths, decision-making, and communication."]},
  {id:359,domain:G,question:"What is the difference between symmetric and asymmetric encryption in terms of key management?",options:["Symmetric and asymmetric encryption both use identical key generation, distribution, and storage management procedures","Asymmetric encryption can only function correctly when dedicated hardware security modules generate and store its keys","Symmetric encryption requires two separate keys for each party; asymmetric encryption relies on only a single shared key","Symmetric uses a single shared secret key; asymmetric uses a public/private key pair"],answer:3,explanation:"Symmetric key distribution is the challenge (how to share the secret securely); asymmetric solves this with freely shareable public keys.",optionExplanations:["Symmetric and asymmetric encryption have fundamentally different key management approaches — the public/private pair eliminates the secure key distribution problem that symmetric keys face.","While HSMs can optionally store asymmetric keys for added protection, they are not required — asymmetric keys can also be stored in ordinary software keystores.","This reverses the actual relationship — symmetric encryption uses a single shared key, while asymmetric encryption is what actually uses a pair of keys.","Symmetric encryption uses one key for both encryption and decryption, requiring secure key exchange; asymmetric uses key pairs where the public key can be freely shared."]},
  {id:360,domain:T,question:"What is credential stuffing?",options:["Using stolen username/password pairs from one breach to attempt login on other services","Embedding hardcoded default credentials directly inside malware or firmware for later attacker access","Creating fake or synthetic credentials for use in internal software testing and quality assurance","Systematically brute-forcing password hashes offline until the correct plaintext password is discovered"],answer:0,explanation:"Credential stuffing exploits password reuse — attackers take breach dumps and try those credentials against banks, email, and other high-value sites.",optionExplanations:["Credential stuffing uses credential databases from previous breaches to automate login attempts across many services, exploiting password reuse.","Embedding hardcoded credentials in malware or firmware is a persistence technique; credential stuffing is instead an automated attack that reuses breached login data.","Creating synthetic test credentials is a legitimate development and QA practice; credential stuffing instead uses real stolen credentials against live services.","Brute forcing hashes is an offline cracking technique against captured hash values; credential stuffing instead attempts live logins using complete stolen username/password pairs."]},
  {id:361,domain:A,question:"What is a software-defined perimeter (SDP)?",options:["A virtualized firewall appliance that inspects and filters traffic passing between segmented cloud network zones","A traditional demilitarized zone architecture implemented entirely through software-defined networking tools","A security framework that dynamically creates one-to-one connections between authorized users and the resources they access","A cloud-hosted intrusion detection system that monitors network traffic for known malicious attack signatures"],answer:2,explanation:"SDP hides network resources until after authentication and authorization, making infrastructure invisible to unauthorized users (implements zero trust).",optionExplanations:["Virtual firewalls inspect and filter traffic between segments; SDP instead makes resources completely invisible until a user is authenticated and authorized.","A software-defined DMZ is still a traditional perimeter network zone; SDP eliminates the perimeter concept entirely by hiding resources until access is granted.","SDP (also called black cloud) authenticates users first, then dynamically provisions encrypted connections only to authorized resources, never exposing the network.","Cloud-based IDS monitors traffic for known threats and signatures; SDP instead controls access by making resources invisible to unauthenticated users."]},
  {id:362,domain:O,question:"What is the purpose of a business impact analysis (BIA)?",options:["Reviewing routine IT system performance metrics such as uptime, latency, and resource utilization","Assessing individual employee productivity levels across departments to identify staffing inefficiencies","Identifying critical business functions and quantifying the impact of their disruption on the organization","Analyzing competitor business strategies and market positioning to inform executive decision-making"],answer:2,explanation:"The BIA identifies critical functions, recovery time objectives (RTO), recovery point objectives (RPO), and financial impact of downtime.",optionExplanations:["IT performance metrics are day-to-day operational monitoring; a BIA instead establishes business recovery requirements that drive continuity planning.","Employee productivity assessment is an HR management concern; a BIA instead focuses on process criticality and quantifying disruption impact.","A BIA identifies which processes are most critical, the maximum tolerable downtime, data loss tolerance, and financial/reputational impact of disruptions.","Competitor strategy analysis is a business intelligence and marketing activity; a BIA instead focuses on internal operations and their recovery requirements."]},
  {id:363,domain:T,question:"What is a living off the land (LotL) attack technique?",options:["Using legitimate built-in system tools such as PowerShell or WMI to conduct malicious activity without custom malware","Physically planting rogue hardware devices inside a target's facilities to intercept network traffic","Attacking internet-connected IoT sensors and equipment specifically within agricultural or farming environments","Using social engineering tactics such as impersonation to gain unauthorized physical access to a building"],answer:0,explanation:"LotL attacks abuse trusted tools already present on systems, making detection difficult since the tools are legitimate and expected to run.",optionExplanations:["LotL attackers use PowerShell, WMI, certutil, and other built-in Windows/Linux tools to evade detection because these tools are expected to be running.","Planting physical hardware devices is a hardware-based intrusion technique; LotL instead relies entirely on software tools already present on the system.","LotL is a general technique applicable to any environment and is not specific to agricultural equipment or IoT contexts.","Gaining physical access through social engineering is a distinct attack vector; LotL refers specifically to abusing native system tools already installed on a machine."]},
  {id:364,domain:G,question:"What is the role of a certificate revocation list (CRL)?",options:["A curated list of trusted root certificate authorities preinstalled in an operating system's trust store","A comprehensive registry tracking every certificate a certificate authority has ever issued","An internal list maintained by a certificate authority of certificates that are pending renewal","A published list of certificates that have been revoked before their expiration date"],answer:3,explanation:"CRLs allow relying parties to check if a certificate has been revoked due to key compromise, CA compromise, or policy violation.",optionExplanations:["Trusted root certificates are stored in a device's trust store for validating chains; a CRL instead lists certificates that have been revoked.","A full issuance registry tracks all certificates ever created; a CRL specifically lists only certificates that are no longer trustworthy despite not yet expiring.","Renewal-pending lists are managed internally by certificate authorities for administrative purposes; a CRL instead publicly publishes revocation status.","A CRL lists certificate serial numbers that have been invalidated, allowing clients to verify a certificate hasn't been revoked before trusting it."]},
  {id:365,domain:P,question:"What is a privacy impact assessment (PIA)?",options:["A technical review evaluating the strength of an organization's network security controls","A structured assessment evaluating the physical security controls protecting a data center facility","A systematic process for evaluating the privacy risks of collecting or processing personal information","A compliance audit verifying that all employees have completed required privacy training courses"],answer:2,explanation:"PIAs identify how personal data will be collected, used, stored, and shared, and assess risks to individuals' privacy rights.",optionExplanations:["Network security control reviews are technical assessments of infrastructure; a PIA instead focuses on the legal and ethical dimensions of handling personal data.","Physical security assessments evaluate facility-level controls like locks and cameras; a PIA instead analyzes risks related to personal data privacy.","A PIA examines the data lifecycle — what's collected, why, how long kept, who can access it — and identifies risks and mitigations for privacy rights.","Training completion audits are compliance checks on staff education; a PIA is instead a risk assessment of a specific data processing activity."]},
  {id:366,domain:A,question:"What is microsegmentation in cloud and virtualized environments?",options:["Deploying each application into its own physically separate cloud region for geographic redundancy","Applying fine-grained security policies at the workload level to control east-west traffic between workloads","Dividing a single physical server's hardware resources into several independent virtual machines","Segmenting and prioritizing network traffic strictly according to packet size and bandwidth consumption"],answer:1,explanation:"Microsegmentation applies policies between individual VMs or containers, preventing lateral movement even within the same network segment.",optionExplanations:["Using separate cloud regions provides geographic redundancy and disaster recovery; microsegmentation instead provides granular security policy enforcement within an environment.","Microsegmentation enforces security policies at the workload level, controlling traffic between individual services and preventing attackers from moving laterally between systems.","Creating multiple VMs from one physical server is virtualization itself; microsegmentation is instead a security policy applied on top of those VMs.","Segmenting traffic by packet size is a quality-of-service concept; microsegmentation is instead about enforcing security policy between individual workloads."]},
  {id:367,domain:O,question:"What is threat hunting?",options:["Proactively searching through networks and systems for signs of compromise that evaded automated detection","Deploying decoy honeypot systems specifically designed to lure and distract attackers","Running scheduled automated vulnerability scans to identify unpatched software across the network","Reactively investigating and responding to alerts already generated by automated security tools"],answer:0,explanation:"Threat hunters assume compromise has occurred and use hypotheses, data analysis, and security expertise to find hidden attackers.",optionExplanations:["Threat hunting is a proactive, analyst-driven search for adversaries using TTPs, hypotheses, and anomaly analysis to find what automated tools missed.","Honeypots are a deception technology deployed passively; threat hunting instead actively searches production systems for existing signs of compromise.","Automated vulnerability scanning identifies known weaknesses on a schedule; threat hunting instead looks for active adversaries that have already evaded defenses.","Responding to existing alerts is reactive security operations; threat hunting is instead proactive and assumes automated detection has already failed to catch something."]},
  {id:368,domain:T,question:"What is a command and control (C2) server in the context of malware?",options:["A legitimate vendor-operated server that distributes verified software patches and updates","A security appliance server that automatically detects and removes malware from endpoints","A dedicated server that centrally manages user authentication and single sign-on credentials","Infrastructure controlled by attackers that sends commands to and receives data from compromised machines"],answer:3,explanation:"C2 infrastructure allows attackers to control botnets and malware remotely, issuing instructions and exfiltrating data from compromised hosts.",optionExplanations:["Legitimate software update servers are trusted infrastructure; C2 servers are malicious infrastructure that sometimes mimics legitimate update traffic to blend in.","Security tools detect and remove malware from infected systems; C2 servers instead enable attackers to operate and direct that same malware remotely.","Authentication servers manage legitimate user identity and login; C2 servers instead control already-compromised endpoint machines.","C2 (or C&C) servers are attacker-controlled infrastructure that maintains communication with malware on victim systems, enabling remote control and data exfiltration."]},
  {id:369,domain:G,question:"What is forward secrecy (perfect forward secrecy)?",options:["A property ensuring that session keys are not compromised even if the server's private key is later compromised","Pre-generating and encrypting future communications well in advance of when the actual session or conversation takes place","Automatically generating backup cryptographic keys shortly before an existing certificate is due to expire","Simultaneously forwarding the same encrypted packets to multiple redundant destination servers for reliability"],answer:0,explanation:"PFS uses ephemeral key exchange (ECDHE/DHE) so each session has a unique key — past traffic stays secure even if the private key is stolen later.",optionExplanations:["Perfect forward secrecy generates ephemeral session keys that are discarded after use, so compromising the long-term private key cannot decrypt recorded past sessions.","Pre-encrypting future communications in advance is not a real cryptographic concept; PFS instead protects past sessions from a future compromise of the private key.","Generating backup keys ahead of expiration is routine key management; PFS is instead a property of ephemeral key exchange protocols like ECDHE.","Forwarding encrypted packets to multiple destinations is a routing and redundancy concept; PFS is instead a key exchange property protecting past session keys."]},
  {id:370,domain:O,question:"What is the difference between RTO and RPO in disaster recovery?",options:["RTO is the maximum acceptable downtime before recovery; RPO is the maximum acceptable data loss measured in time","RTO and RPO are essentially identical metrics that measure the exact same recovery characteristic","RPO measures how quickly systems are restored, while RTO measures how frequently data backups are taken","RTO applies only to database systems, while RPO applies only to application-layer services"],answer:0,explanation:"RTO (Recovery Time Objective) defines how quickly systems must be restored; RPO (Recovery Point Objective) defines how much data loss is acceptable.",optionExplanations:["RTO asks 'how long can we be down?' (e.g., 4 hours); RPO asks 'how much data can we lose?' (e.g., last 1 hour of transactions).","RTO and RPO are distinct metrics addressing different aspects of recovery — downtime tolerance versus data loss tolerance — not identical measurements.","This reverses the definitions — RPO actually determines the backup frequency needed to limit data loss, while RTO determines how quickly systems must be restored.","Both RTO and RPO apply to any critical system or application being protected, not to specific technology categories like databases versus applications."]},
  {id:371,domain:T,question:"What is a rootkit?",options:["Malware that gains and hides deep OS-level access, concealing its presence and other malware from the system","A bundled collection of legitimate administrator scripts used for routine system maintenance tasks","A legitimate remote access tool used by IT support staff to manage systems","An administrative utility used for managing privileged system root and superuser accounts"],answer:0,explanation:"Rootkits modify the OS kernel or bootloader to hide processes, files, and network connections, making detection and removal extremely difficult.",optionExplanations:["Rootkits subvert OS functions to hide malicious activity — they intercept system calls to filter out their own processes, files, and registry keys from security tools.","Administrator scripts are legitimate management tools used openly by IT staff; rootkits are malicious and specifically designed for stealth and concealment.","Legitimate remote access tools (RATs used for support) provide authorized remote control; rootkits specifically provide stealth by hiding the attacker's unauthorized presence.","Root account management tools control legitimate privileges for administrators; rootkits instead exploit root or kernel access to persist and hide from detection."]},
  {id:372,domain:A,question:"What is a web application firewall (WAF) designed to protect against?",options:["Large-scale network-level distributed denial-of-service attacks that flood bandwidth and infrastructure","Application-layer attacks targeting web applications, such as SQL injection, XSS, and CSRF","Malware infections spreading across individual employee endpoint devices and workstations","Unauthorized physical access attempts to the data center housing web servers"],answer:1,explanation:"WAFs inspect HTTP/HTTPS traffic and block attacks targeting application logic — things traditional network firewalls cannot detect.",optionExplanations:["Network-level DDoS is mitigated by dedicated anti-DDoS services and network firewalls; WAFs instead protect the web application logic layer.","WAFs analyze HTTP requests and responses, detecting and blocking application-layer attacks like SQL injection, XSS, path traversal, and bot attacks.","Endpoint malware is addressed by antivirus and EDR tools installed on devices; WAFs instead protect web applications from remote attacks.","Physical access controls like badges and locks are a separate concern; WAFs protect against remote application-layer attacks delivered over the network."]},
  {id:373,domain:P,question:"What is the right to erasure (right to be forgotten) under GDPR?",options:["A right allowing individuals to formally access and review all data an organization holds about them","An individual's right to request deletion of their personal data when it is no longer necessary or consent is withdrawn","The right for any individual to request the deletion of any other person's personal data","The right to object to and prevent solely automated decision-making processes that produce legal effects"],answer:1,explanation:"Article 17 GDPR allows individuals to request deletion of their personal data under specific circumstances, including withdrawal of consent.",optionExplanations:["The right of access under Article 15 allows individuals to see what data is held; erasure under Article 17 instead allows them to request its deletion.","GDPR Article 17 gives individuals the right to request organizations delete their personal data when processing is no longer justified, consent is withdrawn, or data was processed unlawfully.","The right to erasure applies only to one's own personal data — individuals cannot request the deletion of another person's data under this right.","The right to object to automated decision-making is a separate provision under GDPR Article 22; erasure is a distinct right found in Article 17."]},
  {id:374,domain:G,question:"What is salting in the context of password storage?",options:["Enforcing minimum complexity requirements such as length and special characters on new passwords","Encrypting all stored passwords centrally using a single shared master encryption key","Compressing the entire password database to reduce its overall storage footprint","Adding a unique random value to each password before hashing to prevent rainbow table attacks"],answer:3,explanation:"Salts ensure identical passwords produce different hashes, defeating precomputed rainbow table attacks and making per-password cracking necessary.",optionExplanations:["Password complexity requirements are a policy control enforced at creation time; salting is instead a technical hash-protection mechanism applied during storage.","Encrypting passwords with a shared key is a different mechanism than hashing entirely; salting is instead a technique applied alongside hashing, not encryption.","Compressing a password database is a storage optimization technique; salting is instead a security technique that protects individual password hashes from precomputed attacks.","A salt is a unique random string prepended or appended to each password before hashing, ensuring two identical passwords produce completely different stored hashes."]},
  {id:375,domain:O,question:"What is the purpose of security orchestration, automation, and response (SOAR)?",options:["Providing a single unified dashboard that consolidates alerts from every security tool deployed","Continuously performing automated penetration tests against production systems to uncover weaknesses","Automating repetitive security tasks and coordinating responses across security tools to improve efficiency","Fully replacing human security analysts with autonomous systems that require no human oversight"],answer:2,explanation:"SOAR platforms run playbooks to automatically triage alerts, enrich data, contain threats, and coordinate multi-tool response actions.",optionExplanations:["A unified dashboard is a feature commonly found in SIEM and security operations platforms; SOAR is instead about automated action and workflow orchestration.","Automated penetration testing tools are separate specialized security products; SOAR instead focuses on detecting and responding to real ongoing incidents.","SOAR platforms automate repetitive tasks (IP lookups, ticket creation, containment actions) and orchestrate workflows across SIEM, EDR, firewall, and ticketing systems.","SOAR augments and supports security analysts rather than replacing them; human judgment remains essential for complex investigative decisions."]},
  {id:376,domain:T,question:"What is pretexting in social engineering?",options:["Directly threatening a target with legal or criminal consequences to coerce them into compliance","Setting up fraudulent look-alike websites designed to capture visitors' entered login credentials","Sending mass, generic phishing emails to as many recipients as possible","Creating a fabricated scenario or false identity to manipulate a target into providing information or access"],answer:3,explanation:"Pretexting involves creating a believable false context (impersonating IT support, auditors, vendors) to make targets comply with requests.",optionExplanations:["Threatening legal action is an intimidation-based tactic; pretexting instead uses persuasion through a fabricated false identity rather than overt threats.","Fake websites for credential capture describe pharming or phishing; pretexting is instead a social manipulation technique centered on human interaction.","Mass phishing emails are broad, untargeted attacks without a sophisticated pretext; pretexting instead involves crafting a specific, believable narrative.","Pretexting builds a detailed false scenario to establish trust — pretending to be a coworker needing urgent help, an auditor requiring access, or a vendor verifying an order."]},
  {id:377,domain:A,question:"What is the purpose of a hardware security module (HSM)?",options:["Encrypting the contents of hard drives using standard software-based full-disk encryption methods","Continuously monitoring hardware component temperatures to prevent overheating and system failure","Providing physical locking mechanisms and security measures for equipment racks inside a data center","A tamper-resistant hardware device that securely stores cryptographic keys and performs cryptographic operations"],answer:3,explanation:"HSMs protect private keys by ensuring they never leave the hardware boundary, with tamper-evident mechanisms that destroy keys if tampering is detected.",optionExplanations:["Disk encryption software can use cryptographic keys during its operation; HSMs are instead the protected hardware where such keys are generated and securely stored.","Temperature monitoring is an infrastructure management function; HSMs instead perform cryptographic operations using keys stored in protected hardware.","Physical rack security involves locks and access controls for equipment; HSMs instead specifically protect cryptographic key material.","HSMs are purpose-built hardware devices with physical tamper protection that generate, store, and use keys — private keys never leave the HSM in plaintext."]},
  {id:378,domain:O,question:"What is the mean time to detect (MTTD) security metric?",options:["The typical elapsed duration of a distributed denial-of-service attack against a target","The average time employees take to complete their mandatory annual security awareness training","The average time from when a threat actor gains access until the organization detects the compromise","The average time required to identify and fully remediate a discovered software vulnerability"],answer:2,explanation:"MTTD measures detection capability — lower is better. The industry average has historically been months, giving attackers time to cause significant damage.",optionExplanations:["DDoS attack duration varies by campaign and target; MTTD instead measures how quickly an organization detects any type of compromise, not attack length.","Security training completion time is a compliance and HR metric; MTTD is instead an operational measurement of security detection effectiveness.","MTTD measures the gap between initial compromise and discovery, representing the attacker's dwell time and opportunity to cause damage.","Average time to remediate vulnerabilities is measured by MTTR (Mean Time to Repair); MTTD is instead specifically about the speed of detection."]},
];
